struct ImageIntrinsicProbeOutcome {
  intrinsic_size: Option<Size>,
  aspect_ratio: Option<f32>,
  explicit_no_ratio: bool,
  is_placeholder: bool,
}

fn intrinsic_axis_is_known(value: f32) -> bool {
  value.is_finite() && value > 0.0
}

fn aspect_ratio_is_usable(value: f32) -> bool {
  value.is_finite() && value > 0.0
}

fn intrinsic_size_is_complete(size: Size) -> bool {
  intrinsic_axis_is_known(size.width) && intrinsic_axis_is_known(size.height)
}

fn complete_intrinsic_size_with_ratio(size: Size, ratio: f32) -> Option<Size> {
  if !aspect_ratio_is_usable(ratio) {
    return None;
  }
  let width_known = intrinsic_axis_is_known(size.width);
  let height_known = intrinsic_axis_is_known(size.height);
  match (width_known, height_known) {
    (true, false) => Some(Size::new(size.width, size.width / ratio)),
    (false, true) => Some(Size::new(size.height * ratio, size.height)),
    _ => None,
  }
}

struct ImageProbePrefetchJoinHandle(Option<std::thread::JoinHandle<()>>);

impl Drop for ImageProbePrefetchJoinHandle {
  fn drop(&mut self) {
    if let Some(handle) = self.0.take() {
      let _ = handle.join();
    }
  }
}

fn authored_intrinsic_axis_hints(intrinsic_size: Option<Size>) -> (Option<f32>, Option<f32>) {
  let Some(size) = intrinsic_size else {
    return (None, None);
  };
  let width = (size.width.is_finite() && size.width > 0.0).then_some(size.width);
  let height = (size.height.is_finite() && size.height > 0.0).then_some(size.height);
  (width, height)
}

fn trim_ascii_whitespace(value: &str) -> &str {
  value.trim_matches(|c: char| matches!(c, '\u{0009}' | '\u{000A}' | '\u{000C}' | '\u{000D}' | ' '))
}

fn trim_ascii_whitespace_and_trailing_semicolon(value: &str) -> &str {
  let trimmed = trim_ascii_whitespace(value);
  trim_ascii_whitespace(trimmed.trim_end_matches(';'))
}

/// Preserve a non-empty fragment identifier from `fragment_source_url` onto `candidate_url`.
///
/// This is primarily used for browser-like navigation: URL fragments are not sent to servers, so
/// they can be lost when we derive `final_url` from an HTTP response/redirect chain. We still need
/// the fragment for `:target` / `:target-within` selector matching and browser UI history.
fn merge_fragment_from_url(candidate_url: &str, fragment_source_url: &str) -> String {
  let Ok(fragment_source) = Url::parse(fragment_source_url) else {
    return candidate_url.to_string();
  };
  let Some(fragment) = fragment_source.fragment().filter(|f| !f.is_empty()) else {
    return candidate_url.to_string();
  };

  if let Ok(mut parsed) = Url::parse(candidate_url) {
    parsed.set_fragment(Some(fragment));
    return parsed.to_string();
  }

  // Fall back to string surgery for opaque/invalid URLs.
  let base = candidate_url
    .split_once('#')
    .map(|(before, _)| before)
    .unwrap_or(candidate_url);
  format!("{base}#{fragment}")
}

fn url_looks_like_svg_resource(url: &str) -> bool {
  let trimmed = trim_ascii_whitespace(url);
  if trimmed.is_empty() {
    return false;
  }

  // Inline SVG markup and percent-encoded `<svg` strings should be treated as SVG resources.
  if trimmed.starts_with('<')
    || trimmed
      .get(.."%3csvg".len())
      .is_some_and(|prefix| prefix.eq_ignore_ascii_case("%3csvg"))
  {
    return true;
  }

  if trimmed
    .get(.."data:image/svg+xml".len())
    .is_some_and(|prefix| prefix.eq_ignore_ascii_case("data:image/svg+xml"))
  {
    return true;
  }

  let base = trimmed
    .split(|c: char| c == '?' || c == '#')
    .next()
    .unwrap_or(trimmed);
  base
    .get(base.len().saturating_sub(4)..)
    .is_some_and(|suffix| suffix.eq_ignore_ascii_case(".svg"))
    || base
      .get(base.len().saturating_sub(5)..)
      .is_some_and(|suffix| suffix.eq_ignore_ascii_case(".svgz"))
}

fn image_sources_might_be_svg(
  src: &str,
  srcset: &[crate::tree::box_tree::SrcsetCandidate],
  picture_sources: &[crate::tree::box_tree::PictureSource],
) -> bool {
  if url_looks_like_svg_resource(src) {
    return true;
  }
  for candidate in srcset {
    if url_looks_like_svg_resource(&candidate.url) {
      return true;
    }
  }
  for source in picture_sources {
    if source
      .mime_type
      .as_deref()
      .is_some_and(|mime| mime.eq_ignore_ascii_case("image/svg+xml"))
    {
      return true;
    }
    for candidate in &source.srcset {
      if url_looks_like_svg_resource(&candidate.url) {
        return true;
      }
    }
  }
  false
}

/// Main entry point for the FastRender library
///
/// `FastRender` provides a high-level API for rendering HTML/CSS to pixels.
/// It manages internal resources like font contexts and layout engines,
/// providing a simple interface for common rendering tasks.
///
/// # Examples
///
/// ## Basic rendering
///
/// ```rust,no_run
/// # use fastrender::api::FastRender;
/// # fn main() -> fastrender::Result<()> {
///
/// let mut renderer = FastRender::new()?;
/// let pixmap = renderer.render_html("<h1>Hello!</h1>", 800, 600)?;
/// # Ok(())
/// # }
/// ```
///
/// ## With builder pattern
///
/// ```rust,no_run
/// # use fastrender::api::{FastRender, FastRenderConfig};
/// # use fastrender::Rgba;
/// # fn main() -> fastrender::Result<()> {
///
/// let config = FastRenderConfig::new()
///     .with_default_background(Rgba::WHITE);
///
/// let mut renderer = FastRender::with_config(config)?;
/// let html = "<h1>Hello!</h1>";
/// let pixmap = renderer.render_html(html, 1024, 768)?;
/// # Ok(())
/// # }
/// ```
///
/// ## Access to intermediate structures
///
/// ```rust,no_run
/// # use fastrender::api::FastRender;
/// # fn main() -> fastrender::Result<()> {
///
/// let mut renderer = FastRender::new()?;
///
/// // Parse HTML to DOM
/// let dom = renderer.parse_html("<div>Content</div>")?;
///
/// // Layout the document
/// let fragment_tree = renderer.layout_document(&dom, 800, 600)?;
///
/// // Paint to pixmap
/// let pixmap = renderer.paint(&fragment_tree, 800, 600)?;
/// # Ok(())
/// # }
/// ```
pub struct FastRender {
  /// Font context for text shaping and measurement
  font_context: FontContext,

  /// Shared text shaping pipeline used for ad-hoc shaping (e.g. measuring alt text when an image
  /// cannot be loaded). Keeping this on the renderer avoids repeatedly constructing per-call caches
  /// (including the fallback cache) in hot loops.
  shaping_pipeline: ShapingPipeline,

  /// Layout engine for computing positions
  layout_engine: LayoutEngine,

  /// Image cache for external resources (images, SVG)
  image_cache: ImageCache,

  /// Resource fetcher for loading external resources (shared with ImageCache)
  fetcher: Arc<dyn ResourceFetcher>,

  /// Optional diagnostics sink for recording fetch failures during a render.
  diagnostics: Option<Arc<Mutex<RenderDiagnostics>>>,

  /// Default background color for rendering
  background_color: Rgba,

  /// Default viewport width for render()
  default_width: u32,

  /// Default viewport height for render()
  default_height: u32,

  /// Device pixel ratio used for media queries and resolution-dependent resources
  device_pixel_ratio: f32,

  /// Whether to honor `<meta name="viewport">` directives when computing the
  /// layout viewport for screen media.
  apply_meta_viewport: bool,

  /// Whether to honor `<meta name="color-scheme">` directives as a UA `color-scheme` baseline.
  apply_meta_color_scheme: bool,

  /// When true, expand the paint canvas to cover the laid-out content bounds.
  fit_canvas_to_content: bool,

  /// Base URL used for resolving links/targets
  base_url: Option<String>,

  /// True document URL for this render (after redirects), used for origin/referrer policy.
  ///
  /// Note: This is intentionally distinct from [`FastRender::base_url`], which may incorporate a
  /// `<base href>` override for resolving relative references.
  document_url: Option<String>,

  /// The Content Security Policy (CSP) applied to the current document, if known.
  ///
  /// This is populated from:
  /// - `Content-Security-Policy` HTTP response headers when loading via [`FastRender::prepare_url`]
  /// - `<meta http-equiv="Content-Security-Policy">` tags discovered during DOM parsing
  ///
  /// This is stored separately from [`FastRender::resource_context`] so consumers like
  /// `api::BrowserTab` can enforce CSP in pipelines that are not driven by the renderer's
  /// subresource loader.
  document_csp: Option<CspPolicy>,

  /// Compatibility profile for opt-in site-specific behaviors
  compat_profile: CompatProfile,

  /// Optional compatibility mode applied during DOM parsing
  dom_compat_mode: DomCompatibilityMode,

  /// Whether HTML parsing should use "scripting enabled" semantics (e.g. `<noscript>` handling).
  ///
  /// Note: This does not execute scripts; it only affects HTML parsing and downstream render
  /// semantics for elements like `<noscript>`. This value is also used as the default for Media
  /// Queries Level 5 `(scripting: ...)` evaluation unless overridden by runtime toggles.
  dom_scripting_enabled: bool,

  /// Whether `render_html`/`render_url` parse HTML with "scripting enabled" semantics.
  ///
  /// This affects html5ever's parsing behavior for elements such as `<noscript>`, but it does **not**
  /// execute scripts.
  render_parse_scripting_enabled: bool,

  /// Manual fragmentation options when no `@page` rules are present.
  fragmentation: Option<FragmentationOptions>,

  /// Resource loading policy configuration.
  resource_policy: ResourceAccessPolicy,

  /// Active resource context for the current render.
  resource_context: Option<ResourceContext>,

  /// Maximum iframe nesting depth when painting nested browsing contexts
  max_iframe_depth: usize,

  /// Runtime debug/configuration toggles in effect for this renderer instance.
  runtime_toggles: Arc<RuntimeToggles>,

  /// Parallel paint configuration for the display-list renderer.
  paint_parallelism: PaintParallelism,

  /// Parallel layout configuration for fan-out across independent subtrees.
  layout_parallelism: LayoutParallelism,
}

impl std::fmt::Debug for FastRender {
  fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
    f.debug_struct("FastRender")
      .field("background_color", &self.background_color)
      .field("default_width", &self.default_width)
      .field("default_height", &self.default_height)
      .field("device_pixel_ratio", &self.device_pixel_ratio)
      .field("apply_meta_viewport", &self.apply_meta_viewport)
      .field("apply_meta_color_scheme", &self.apply_meta_color_scheme)
      .field("fit_canvas_to_content", &self.fit_canvas_to_content)
      .field("base_url", &self.base_url)
      .field("compat_profile", &self.compat_profile)
      .field("dom_compat_mode", &self.dom_compat_mode)
      .field("dom_scripting_enabled", &self.dom_scripting_enabled)
      .field(
        "render_parse_scripting_enabled",
        &self.render_parse_scripting_enabled,
      )
      .field("fragmentation", &self.fragmentation)
      .field("resource_policy", &self.resource_policy)
      .field("max_iframe_depth", &self.max_iframe_depth)
      .field("paint_parallelism", &self.paint_parallelism)
      .field("layout_parallelism", &self.layout_parallelism)
      .finish_non_exhaustive()
  }
}

/// Configuration for FastRender
///
/// Use this to customize rendering behavior when creating a FastRender instance.
///
/// # Examples
///
/// ```rust,no_run
/// use fastrender::api::FastRenderConfig;
/// use fastrender::Rgba;
///
/// let config = FastRenderConfig::new()
///     .with_default_background(Rgba::rgb(240, 240, 240));
/// ```
#[derive(Debug, Clone)]
pub struct FastRenderConfig {
  /// Default background color for rendered images
  pub background_color: Rgba,

  /// Default viewport width (used when not specified)
  pub default_width: u32,

  /// Default viewport height (used when not specified)
  pub default_height: u32,

  /// Device pixel ratio used for media queries and resolution-dependent resources
  pub device_pixel_ratio: f32,

  /// Base URL used to resolve relative resource references (images, CSS)
  pub base_url: Option<String>,

  /// Optional in-memory resource cache configuration. If `None`, caching is disabled.
  pub resource_cache: Option<CachingFetcherConfig>,

  /// Policy controlling which resources may be fetched and how large they may be.
  pub resource_policy: ResourcePolicy,

  /// Maximum iframe nesting depth when painting nested browsing contexts
  pub max_iframe_depth: usize,

  /// Allow http(s) documents to load file:// resources when true (disabled by default)
  pub allow_file_from_http: bool,

  /// Block mixed HTTP subresources when the document is HTTPS.
  pub block_mixed_content: bool,
  /// Restrict subresource loads (CSS/images/fonts/etc.) to the document origin (plus allowlist) when true.
  ///
  /// Note: this does not block cross-origin iframe/embed document navigation.
  pub same_origin_subresources: bool,

  /// Additional origins allowed when `same_origin_subresources` is enabled.
  pub allowed_subresource_origins: Vec<DocumentOrigin>,

  /// Compatibility profile controlling opt-in site-specific behaviors.
  pub compat_profile: CompatProfile,

  /// Optional compatibility mode used when parsing HTML.
  pub dom_compat_mode: DomCompatibilityMode,

  /// Whether HTML parsing should use "scripting enabled" semantics (e.g. `<noscript>` handling).
  ///
  /// This maps to `html5ever::tree_builder::TreeBuilderOpts::scripting_enabled`, but FastRender
  /// still does not execute scripts. When enabled, `<noscript>` fallback content is suppressed
  /// to match JS-enabled browser parsing behavior.
  ///
  /// Note: This controls the public parse APIs (`FastRender::parse_html` / `parse_html_dom2`).
  /// The render pipeline has separate parsing semantics controlled by
  /// [`FastRenderConfig::render_parse_scripting_enabled`].
  ///
  /// This also sets the default value of the Media Queries Level 5 `(scripting: ...)` media
  /// feature during rendering. Runtime toggles (e.g. `FASTR_SCRIPTING`) take precedence.
  pub dom_scripting_enabled: bool,

  /// Whether `render_html`/`render_url` parse the input HTML with "scripting enabled" semantics.
  ///
  /// This maps to `DomParseOptions.scripting_enabled` used by FastRender's internal
  /// `parse_html_for_render` step (and therefore affects `<noscript>` tokenization), but it does
  /// **not** execute scripts.
  ///
  /// Defaults to `true` to match Chrome baselines captured with CSP `script-src` blocked (script
  /// execution disabled, but HTML parsing semantics still "scripting enabled").
  pub render_parse_scripting_enabled: bool,

  /// Whether to honor `<meta name="viewport">` when computing the layout viewport.
  pub apply_meta_viewport: bool,

  /// Whether to honor `<meta name="color-scheme">` as a UA `color-scheme` baseline.
  pub apply_meta_color_scheme: bool,

  /// Optional pagination/fragmentation configuration applied when no `@page` rules are present.
  pub fragmentation: Option<FragmentationOptions>,

  /// When true, expand the paint canvas to fit the laid-out content bounds.
  pub fit_canvas_to_content: bool,

  /// Font discovery configuration (system vs bundled fonts, extra search paths).
  pub font_config: FontConfig,

  /// Runtime debug/configuration toggles used for this renderer.
  pub runtime_toggles: Arc<RuntimeToggles>,

  /// Parallel paint configuration for the display-list renderer.
  pub paint_parallelism: PaintParallelism,

  /// Parallel layout configuration for fan-out across independent subtrees.
  pub layout_parallelism: LayoutParallelism,
}

impl Default for FastRenderConfig {
  fn default() -> Self {
    let runtime_toggles = runtime::runtime_toggles();
    let mut paint_parallelism = match runtime_toggles
      .get("FASTR_PAINT_PARALLEL")
      .map(|raw| raw.trim().to_ascii_lowercase())
    {
      Some(raw) => match raw.as_str() {
        "0" | "false" | "off" => PaintParallelism::disabled(),
        "1" | "true" | "on" => PaintParallelism::enabled(),
        "auto" => PaintParallelism::default(),
        _ => {
          if runtime_toggles.truthy_with_default("FASTR_PAINT_PARALLEL", true) {
            PaintParallelism::default()
          } else {
            PaintParallelism::disabled()
          }
        }
      },
      None => PaintParallelism::default(),
    };
    if let Some(max_threads) = runtime_toggles.usize("FASTR_PAINT_PARALLEL_MAX_THREADS") {
      paint_parallelism.max_threads = Some(max_threads.max(1));
    }
    Self {
      background_color: Rgba::WHITE,
      default_width: 800,
      default_height: 600,
      device_pixel_ratio: 1.0,
      base_url: None,
      resource_cache: Some(CachingFetcherConfig::default()),
      resource_policy: ResourcePolicy::default(),
      max_iframe_depth: DEFAULT_MAX_IFRAME_DEPTH,
      allow_file_from_http: false,
      block_mixed_content: false,
      same_origin_subresources: false,
      allowed_subresource_origins: Vec::new(),
      compat_profile: CompatProfile::default(),
      dom_compat_mode: DomCompatibilityMode::Standard,
      dom_scripting_enabled: false,
      render_parse_scripting_enabled: true,
      apply_meta_viewport: false,
      apply_meta_color_scheme: false,
      fragmentation: None,
      fit_canvas_to_content: false,
      font_config: FontConfig::default(),
      runtime_toggles: runtime_toggles.clone(),
      paint_parallelism,
      layout_parallelism: LayoutParallelism::default(),
    }
  }
}

impl FastRenderConfig {
  /// Creates a new configuration with default values
  pub fn new() -> Self {
    Self::default()
  }
}

/// Builder for creating FastRender instances
///
/// # Examples
///
/// ```rust,no_run
/// # use fastrender::{FastRender, Rgba};
/// # fn main() -> fastrender::Result<()> {
///
/// let mut renderer = FastRender::builder()
///     .viewport_size(1024, 768)
///     .background_color(Rgba::WHITE)
///     .build()?;
/// let _ = renderer.render_html("<p>Example</p>", 640, 480)?;
/// # Ok(())
/// # }
/// ```
pub struct FastRenderBuilder {
  config: FastRenderConfig,
  fetcher: Option<Arc<dyn ResourceFetcher>>,
}

impl FastRenderBuilder {
  /// Creates a new builder with default configuration
  pub fn new() -> Self {
    Self {
      config: FastRenderConfig::default(),
      fetcher: None,
    }
  }

  /// Sets the viewport size
  pub fn viewport_size(mut self, width: u32, height: u32) -> Self {
    self.config.default_width = width;
    self.config.default_height = height;
    self
  }

  /// Sets the viewport width
  pub fn viewport_width(mut self, width: u32) -> Self {
    self.config.default_width = width;
    self
  }

  /// Sets the viewport height
  pub fn viewport_height(mut self, height: u32) -> Self {
    self.config.default_height = height;
    self
  }

  /// Sets the background color
  pub fn background_color(mut self, color: Rgba) -> Self {
    self.config.background_color = color;
    self
  }

  /// Sets a base URL used to resolve relative resource references (images, linked CSS)
  pub fn base_url(mut self, url: impl Into<String>) -> Self {
    self.config.base_url = Some(url.into());
    self
  }

  /// Overrides how fonts are discovered and which bundled set to use.
  pub fn font_sources(mut self, font_config: FontConfig) -> Self {
    self.config.font_config = font_config;
    self
  }

  /// Allow loading file:// resources from HTTP(S) documents.
  pub fn allow_file_from_http(mut self, allow: bool) -> Self {
    self.config.allow_file_from_http = allow;
    self
  }

  /// Block mixed HTTP subresources when rendering HTTPS documents.
  pub fn block_mixed_content(mut self, block: bool) -> Self {
    self.config.block_mixed_content = block;
    self
  }

  /// Restrict subresource loads (CSS/images/fonts/etc.) to the document origin (plus any allowlisted origins).
  ///
  /// Note: this does not block cross-origin iframe/embed document navigation.
  pub fn same_origin_subresources(mut self, enabled: bool) -> Self {
    self.config.same_origin_subresources = enabled;
    self
  }

  /// Allow specific origins to load subresources when enforcing same-origin.
  pub fn allowed_subresource_origins(mut self, origins: Vec<DocumentOrigin>) -> Self {
    self.config.allowed_subresource_origins = origins;
    self
  }

  /// Restrict subresource loads (CSS/images/fonts/etc.) to the document origin when true.
  ///
  /// Note: this does not block cross-origin iframe/embed document navigation.
  pub fn with_same_origin_subresources(mut self, enabled: bool) -> Self {
    self.config.same_origin_subresources = enabled;
    self
  }

  /// Allow subresource loads from the provided origins alongside the document origin.
  pub fn with_allowed_subresource_origins(mut self, origins: Vec<DocumentOrigin>) -> Self {
    self.config.allowed_subresource_origins = origins;
    self
  }

  /// Applies `<meta name="viewport">` directives when computing the layout viewport.
  ///
  /// When enabled, `width`/`height` set the layout viewport used for viewport units
  /// and media queries. `initial-scale` (and optional min/max scale) controls zoom,
  /// clamped to the 0.1–10 range, and scales the effective device pixel ratio. The
  /// derived visual viewport is tracked on [`PreparedDocument`] for debugging and
  /// consumers that need to reason about page zoom; `device-width`/`device-height`
  /// media features are evaluated against the emulated screen size instead (see
  /// `HEADLESS_CHROME_SCREEN_SIZE`).
  pub fn apply_meta_viewport(mut self, enabled: bool) -> Self {
    self.config.apply_meta_viewport = enabled;
    self
  }

  /// Applies `<meta name="color-scheme">` directives as a UA `color-scheme` baseline.
  pub fn apply_meta_color_scheme(mut self, enabled: bool) -> Self {
    self.config.apply_meta_color_scheme = enabled;
    self
  }

  /// Expands the paint canvas to fit the laid-out content bounds.
  pub fn fit_canvas_to_content(mut self, enabled: bool) -> Self {
    self.config.fit_canvas_to_content = enabled;
    self
  }

  /// Configures display-list paint parallelism for this renderer.
  pub fn paint_parallelism(mut self, parallelism: PaintParallelism) -> Self {
    self.config.paint_parallelism = parallelism;
    self
  }

  /// Sets the DOM compatibility mode applied during parsing.
  pub fn dom_compatibility_mode(mut self, mode: DomCompatibilityMode) -> Self {
    self.config.dom_compat_mode = mode;
    self
  }

  /// Enables or disables JS-enabled HTML parsing semantics for the public parse APIs
  /// (`FastRender::parse_html` / `parse_html_dom2`) (e.g. `<noscript>` handling).
  ///
  /// This also controls the default value of the Media Queries Level 5 `(scripting: ...)` media
  /// feature during rendering. Runtime toggles (e.g. `FASTR_SCRIPTING`) take precedence.
  ///
  /// Note: `render_html`/`render_url` parsing semantics are controlled separately via
  /// [`FastRenderBuilder::render_parse_scripting_enabled`].
  pub fn dom_scripting_enabled(mut self, enabled: bool) -> Self {
    self.config.dom_scripting_enabled = enabled;
    self
  }

  /// Controls whether `render_html`/`render_url` parse HTML with "scripting enabled" semantics.
  ///
  /// This affects `<noscript>` parsing behavior but does not execute scripts.
  pub fn render_parse_scripting_enabled(mut self, enabled: bool) -> Self {
    self.config.render_parse_scripting_enabled = enabled;
    self
  }

  /// Sets the device pixel ratio used for media queries and image-set selection.
  pub fn device_pixel_ratio(mut self, dpr: f32) -> Self {
    self.config.device_pixel_ratio = dpr;
    self
  }

  /// Enables a specific compatibility profile.
  pub fn compat_mode(mut self, profile: CompatProfile) -> Self {
    self.config.compat_profile = profile;
    self
  }

  /// Turns on site-specific compatibility hacks used for internal captures.
  pub fn with_site_compat_hacks(mut self) -> Self {
    self.config.compat_profile = CompatProfile::SiteCompatibility;
    self
  }

  /// Sets a custom resource policy for fetches performed by this renderer.
  pub fn resource_policy(mut self, policy: ResourcePolicy) -> Self {
    self.config.resource_policy = policy;
    self
  }

  /// Limits nested iframe rendering depth when painting browsing contexts.
  ///
  /// A depth of 0 skips iframe contents entirely. Larger values allow rendering up to that many
  /// nested iframe levels from the current document, with each child iframe inheriting one fewer
  /// level.
  pub fn max_iframe_depth(mut self, depth: usize) -> Self {
    self.config.max_iframe_depth = depth;
    self
  }

  /// Enables pagination/fragmentation when no `@page` rules are present.
  pub fn fragmentation(mut self, options: FragmentationOptions) -> Self {
    self.config.fragmentation = Some(options);
    self
  }

  /// Convenience setter for page-based pagination with an optional gap.
  pub fn paginate(mut self, page_height_css_px: f32, gap_css_px: f32) -> Self {
    self.config.fragmentation =
      Some(FragmentationOptions::new(page_height_css_px).with_gap(gap_css_px));
    self
  }

  /// Convenience setter for column-based fragmentation.
  pub fn columns(mut self, count: usize, gap: f32, fragmentainer_height: f32) -> Self {
    self.config.fragmentation =
      Some(FragmentationOptions::new(fragmentainer_height).with_columns(count, gap));
    self
  }

  /// Sets a custom resource fetcher for loading external resources (images, CSS)
  ///
  /// This allows injection of custom fetching behavior, such as caching or mocking.
  pub fn fetcher(mut self, fetcher: Arc<dyn ResourceFetcher>) -> Self {
    self.fetcher = Some(fetcher);
    self
  }

  /// Builds the FastRender instance
  ///
  /// When the crate is built without the `direct_network` feature, a custom
  /// [`ResourceFetcher`] must be supplied via [`FastRenderBuilder::fetcher`].
  pub fn build(self) -> Result<FastRender> {
    FastRender::with_config_and_fetcher(self.config, self.fetcher)
  }

  /// Overrides the runtime debug/configuration toggles used by the renderer.
  pub fn runtime_toggles(mut self, toggles: RuntimeToggles) -> Self {
    self.config.runtime_toggles = Arc::new(toggles);
    self
  }
}

impl Default for FastRenderBuilder {
  fn default() -> Self {
    Self::new()
  }
}

/// Per-request rendering options for both HTML strings and URLs.
#[derive(Clone)]
pub struct RenderOptions {
  /// Optional viewport override. Falls back to the renderer's default size.
  pub viewport: Option<(u32, u32)>,
  /// Optional device pixel ratio override for media queries and image selection.
  pub device_pixel_ratio: Option<f32>,
  /// Controls structured diagnostics capture for this render.
  pub diagnostics_level: DiagnosticsLevel,
  /// Media type used for evaluating media queries.
  pub media_type: MediaType,
  /// Optional override for whether custom elements match the `:defined` pseudo-class.
  ///
  /// Spec behavior: elements with a valid custom element name are not `:defined` until upgraded.
  /// FastRender does not run the custom elements registry, but defaults to treating custom elements
  /// as defined for compatibility (many pages hide content behind `:not(:defined)`).
  pub treat_custom_elements_as_defined: Option<bool>,
  /// Horizontal scroll offset applied before painting.
  pub scroll_x: f32,
  /// Vertical scroll offset applied before painting.
  pub scroll_y: f32,
  /// Most recent viewport scroll delta (relative offset change).
  pub scroll_delta: Point,
  /// Optional animation/transition sampling time in milliseconds since document load.
  ///
  /// When set, time-based effects such as @starting-style transitions will be sampled at this
  /// moment; when absent, time-based animations resolve to a deterministic settled state.
  ///
  /// Finite animations use their post-animation values, while infinite animations have no
  /// deterministic "final" keyframe state and are ignored (falling back to the underlying style).
  pub animation_time: Option<f32>,
  /// Scroll offsets for element scroll containers keyed by box ID.
  pub element_scroll_offsets: HashMap<usize, Point>,
  /// Most recent scroll deltas for element scroll containers keyed by box ID.
  pub element_scroll_deltas: HashMap<usize, Point>,
  /// Maximum number of external stylesheets to inline. `None` means unlimited.
  pub css_limit: Option<usize>,
  /// When true, include an accessibility tree alongside rendering results.
  pub capture_accessibility: bool,
  /// When true, document fetch failures will return a placeholder pixmap with diagnostics instead of an error.
  pub allow_partial: bool,
  /// When true, follow eligible client-side redirects (e.g. immediate meta refresh) when rendering
  /// a URL.
  ///
  /// Defaults to false to preserve existing behavior.
  pub follow_client_redirects: bool,
  /// Maximum number of eligible client-side redirect hops to follow when `follow_client_redirects`
  /// is enabled.
  pub max_client_redirect_hops: usize,
  /// When true, also follow best-effort early inline JavaScript redirects (e.g.
  /// `location.replace(...)`) when `follow_client_redirects` is enabled.
  pub follow_js_location_redirects: bool,
  /// When Some(true), expand the paint canvas to fit the laid-out content bounds for this render.
  pub fit_canvas_to_content: Option<bool>,
  /// Optional hard timeout for the render.
  pub timeout: Option<Duration>,
  /// Optional best-effort per-stage RSS budget in bytes.
  ///
  /// When set, the renderer samples RSS at stage boundaries (DomParse/Css/Cascade/BoxTree/Layout/Paint)
  /// and aborts the render with [`RenderError::StageMemoryBudgetExceeded`] when the observed RSS
  /// exceeds this budget.
  pub stage_mem_budget_bytes: Option<u64>,
  /// Optional best-effort per-stage allocation budget in bytes.
  ///
  /// When set, known large allocation sites (pixmaps, images, CSS parsing, display list build)
  /// charge best-effort byte estimates to the active stage heartbeat and abort with
  /// [`RenderError::StageAllocationBudgetExceeded`] when the per-stage total exceeds this budget.
  pub stage_alloc_budget_bytes: Option<u64>,
  /// Optional cooperative cancellation callback.
  pub cancel_callback: Option<Arc<CancelCallback>>,
  /// Optional path to write a Chrome trace of this render.
  pub trace_output: Option<PathBuf>,
  /// Optional runtime toggle override for this render.
  pub runtime_toggles: Option<Arc<RuntimeToggles>>,
  /// Optional override for display-list paint parallelism.
  pub paint_parallelism: Option<PaintParallelism>,
  /// Optional override for layout fan-out parallelism.
  pub layout_parallelism: Option<LayoutParallelism>,
  /// Optional iframe embedder hook invoked during paint.
  ///
  /// This can be used to implement site isolation by returning
  /// [`crate::paint::iframe::IframePaintAction::RemotePlaceholder`] for cross-origin iframes.
  pub iframe_embedder: Option<Arc<dyn crate::paint::iframe::IframeEmbedder>>,
}

impl Default for RenderOptions {
  fn default() -> Self {
    Self {
      viewport: None,
      device_pixel_ratio: None,
      animation_time: None,
      diagnostics_level: DiagnosticsLevel::None,
      media_type: MediaType::Screen,
      treat_custom_elements_as_defined: None,
      scroll_x: 0.0,
      scroll_y: 0.0,
      scroll_delta: Point::ZERO,
      element_scroll_offsets: HashMap::new(),
      element_scroll_deltas: HashMap::new(),
      css_limit: None,
      capture_accessibility: false,
      allow_partial: false,
      follow_client_redirects: false,
      max_client_redirect_hops: 3,
      follow_js_location_redirects: false,
      fit_canvas_to_content: None,
      timeout: None,
      stage_mem_budget_bytes: None,
      stage_alloc_budget_bytes: None,
      cancel_callback: None,
      trace_output: None,
      runtime_toggles: None,
      paint_parallelism: None,
      layout_parallelism: None,
      iframe_embedder: None,
    }
  }
}

