  fn paint_with_offset_traced(
    &self,
    fragment_tree: &FragmentTree,
    width: u32,
    height: u32,
    offset: Point,
    paint_parallelism: PaintParallelism,
    scroll_state: &ScrollState,
    media_provider: Option<Arc<dyn crate::media::MediaFrameProvider>>,
    trace: &TraceHandle,
  ) -> Result<Pixmap> {
    let backend = paint_backend_from_env();
    if backend == PaintBackend::Legacy {
      // The legacy painter does not emit a `PaintBuild` heartbeat, so do it here for consistency
      // with the display-list pipeline.
      record_stage(StageHeartbeat::PaintBuild);
    }
    match backend {
      PaintBackend::Legacy => paint_tree_with_resources_scaled_offset_with_trace(
        fragment_tree,
        width,
        height,
        self.background_color,
        self.font_context.clone(),
        self.image_cache.clone(),
        self.device_pixel_ratio,
        offset,
        paint_parallelism,
        scroll_state,
        self.max_iframe_depth,
        media_provider.clone(),
        trace.clone(),
      ),
      PaintBackend::DisplayList => {
        paint_tree_display_list_with_resources_scaled_offset_depth_with_trace(
          fragment_tree,
          width,
          height,
          self.background_color,
          self.font_context.clone(),
          self.image_cache.clone(),
          media_provider.clone(),
          self.device_pixel_ratio,
          offset,
          paint_parallelism,
          scroll_state,
          self.max_iframe_depth,
          trace.clone(),
        )
      }
    }
  }

  /// Renders HTML using shared font/image resources.
  ///
  /// This is primarily used internally when nested rendering is needed (e.g., SVG foreignObject).
  pub(crate) fn render_html_with_resources(
    &self,
    html: &str,
    width: u32,
    height: u32,
    background: Rgba,
  ) -> Result<Pixmap> {
    render_html_with_shared_resources(
      html,
      width,
      height,
      background,
      &self.font_context,
      &self.image_cache,
      Arc::clone(&self.fetcher),
      self.base_url.clone(),
      self.device_pixel_ratio,
      self.resource_policy.clone(),
      self.resource_context.clone(),
      self.max_iframe_depth,
    )
  }

  /// Returns a reference to the font context
  ///
  /// Useful for querying available fonts or font metrics.
  pub fn font_context(&self) -> &FontContext {
    &self.font_context
  }

  /// Returns a mutable reference to the font context
  ///
  /// Useful for loading additional fonts.
  pub fn font_context_mut(&mut self) -> &mut FontContext {
    &mut self.font_context
  }

  /// Returns a reference to the layout engine
  pub fn layout_engine(&self) -> &LayoutEngine {
    &self.layout_engine
  }

  /// Sets the base URL used to resolve relative resource references.
  pub fn set_base_url(&mut self, base_url: impl Into<String>) {
    let base = base_url.into();
    self.base_url = Some(base.clone());
    self.image_cache.set_base_url(base.clone());
    self.layout_engine.image_cache_mut().set_base_url(base);
    self.layout_engine.reset_cached_formatting_contexts();
  }

  /// Replaces the font context used for layout and painting.
  ///
  /// This is primarily used by test harnesses to install a deterministic set
  /// of fonts in CI environments.
  pub fn set_font_context(&mut self, font_context: FontContext) {
    self.font_context = font_context.clone();
    let mut config = self.layout_engine.config().clone();
    config.initial_containing_block.width = self.default_width as f32;
    config.initial_containing_block.height = self.default_height as f32;
    config.parallelism = self.layout_parallelism;
    self.layout_engine = LayoutEngine::with_font_context_and_image_cache(
      config,
      font_context,
      self.image_cache.clone(),
    );
  }

  /// Overrides the device pixel ratio for subsequent renders.
  ///
  /// This is primarily used by test harnesses that need to vary DPR per test case.
  pub fn set_device_pixel_ratio(&mut self, dpr: f32) {
    if dpr.is_finite() && dpr > 0.0 {
      self.device_pixel_ratio = dpr;
    }
  }

  /// Creates a new renderer instance that shares this renderer's expensive immutable resources.
  ///
  /// This is a lightweight alternative to rebuilding a `FastRender` from scratch when a caller
  /// needs one renderer per tab/thread. The cloned renderer:
  /// - shares the resource fetcher, font context, and image cache backing stores,
  /// - copies basic configuration knobs (viewport defaults, DPR, base URL, etc.),
  /// - starts with a fresh set of per-render caches.
  pub(crate) fn clone_for_worker(&self) -> Result<Self> {
    // `FastRender` does not currently retain the full `FastRenderConfig`, so this reconstructs a
    // best-effort config snapshot from the current renderer state. Resource policy limits are
    // enforced by the already-configured fetcher, so the `ResourcePolicy` struct itself can be the
    // default.
    let config = FastRenderConfig {
      background_color: self.background_color,
      default_width: self.default_width,
      default_height: self.default_height,
      device_pixel_ratio: self.device_pixel_ratio,
      base_url: self.base_url.clone(),
      resource_cache: None,
      resource_policy: ResourcePolicy::default(),
      max_iframe_depth: self.max_iframe_depth,
      allow_file_from_http: self.resource_policy.allow_file_from_http,
      block_mixed_content: self.resource_policy.block_mixed_content,
      same_origin_subresources: self.resource_policy.same_origin_only,
      allowed_subresource_origins: self.resource_policy.allowed_origins.clone(),
      compat_profile: self.compat_profile,
      dom_compat_mode: self.dom_compat_mode,
      dom_scripting_enabled: self.dom_scripting_enabled,
      render_parse_scripting_enabled: self.render_parse_scripting_enabled,
      apply_meta_viewport: self.apply_meta_viewport,
      apply_meta_color_scheme: self.apply_meta_color_scheme,
      fragmentation: self.fragmentation,
      fit_canvas_to_content: self.fit_canvas_to_content,
      // `from_parts` uses the provided `FontContext`, so the font discovery config is irrelevant
      // here.
      font_config: FontConfig::default(),
      runtime_toggles: Arc::clone(&self.runtime_toggles),
      paint_parallelism: self.paint_parallelism,
      layout_parallelism: self.layout_parallelism,
    };
    Self::from_parts(
      config,
      Arc::clone(&self.fetcher),
      self.font_context.clone(),
      self.image_cache.clone(),
    )
  }

  /// Clears any configured base URL, leaving relative resources unresolved.
  pub fn clear_base_url(&mut self) {
    self.image_cache.clear_base_url();
    self.layout_engine.image_cache_mut().clear_base_url();
    self.layout_engine.reset_cached_formatting_contexts();
    self.base_url = None;
  }

  fn set_document_url(&mut self, document_url: impl Into<String>) {
    let url = document_url.into();
    if trim_ascii_whitespace(&url).is_empty() {
      self.document_url = None;
    } else {
      self.document_url = Some(url);
    }
  }

  fn clear_document_url(&mut self) {
    self.document_url = None;
  }

  fn document_url(&self) -> Option<&str> {
    self.document_url.as_deref()
  }

  /// Returns the document URL used for resource fetch referrer/origin semantics.
  ///
  /// When rendering HTML strings, callers commonly configure only a base URL. Treat that as the
  /// document URL hint for policy/referrer purposes, while allowing [`FastRender::base_url`] to be
  /// overridden by `<base href>` for URL resolution.
  fn document_url_hint(&self) -> Option<&str> {
    self.document_url().or_else(|| {
      self
        .base_url
        .as_deref()
        .filter(|url| !trim_ascii_whitespace(url).is_empty())
    })
  }

  /// Attach or clear the diagnostics sink for downstream fetchers.
  fn set_diagnostics_sink(&mut self, sink: Option<Arc<Mutex<RenderDiagnostics>>>) {
    self.diagnostics = sink.clone();
    self.image_cache.set_diagnostics_sink(sink.clone());
    self
      .layout_engine
      .image_cache_mut()
      .set_diagnostics_sink(sink);
    self.layout_engine.reset_cached_formatting_contexts();
  }

  fn record_fetch_error(&self, kind: ResourceKind, url: &str, message: impl Into<String>) {
    if let Some(diag) = &self.diagnostics {
      if let Ok(mut guard) = diag.lock() {
        guard.record_error(
          kind,
          url,
          &Error::Resource(ResourceError::new(url.to_string(), message.into())),
        );
      }
    }
  }

  fn build_resource_context(
    &self,
    document_url: Option<&str>,
    diagnostics: Option<SharedRenderDiagnostics>,
    referrer_policy: ReferrerPolicy,
  ) -> ResourceContext {
    let origin = document_url.and_then(origin_from_url);
    let policy = match origin {
      Some(origin) => self.resource_policy.for_origin(Some(origin)),
      None => self.resource_policy.clone(),
    };
    ResourceContext {
      document_url: document_url.map(|url| url.to_string()),
      referrer_policy,
      policy,
      csp: None,
      diagnostics,
      iframe_depth_remaining: Some(self.max_iframe_depth),
      iframe_embedder: None,
    }
  }

  fn push_resource_context(
    &mut self,
    context: Option<ResourceContext>,
  ) -> (
    Option<ResourceContext>,
    Option<ResourceContext>,
    Option<ResourceContext>,
    Option<ResourceContext>,
  ) {
    let prev_self = self.resource_context.clone();
    let prev_image = self.image_cache.resource_context();
    let prev_layout_image = self.layout_engine.image_cache().resource_context();
    let prev_font = self.font_context.resource_context();

    self.resource_context = context.clone();
    self.image_cache.set_resource_context(context.clone());
    self
      .layout_engine
      .image_cache_mut()
      .set_resource_context(context.clone());
    self.layout_engine.reset_cached_formatting_contexts();
    self.font_context.set_resource_context(context);

    (prev_self, prev_image, prev_layout_image, prev_font)
  }

  fn pop_resource_context(
    &mut self,
    prev_self: Option<ResourceContext>,
    prev_image: Option<ResourceContext>,
    prev_layout_image: Option<ResourceContext>,
    prev_font: Option<ResourceContext>,
  ) {
    self.resource_context = prev_self;
    self.image_cache.set_resource_context(prev_image);
    self
      .layout_engine
      .image_cache_mut()
      .set_resource_context(prev_layout_image);
    self.layout_engine.reset_cached_formatting_contexts();
    self.font_context.set_resource_context(prev_font);
  }
  /// Gets the default background color
  pub fn background_color(&self) -> Rgba {
    self.background_color
  }

  /// Sets the default background color
  pub fn set_background_color(&mut self, color: Rgba) {
    self.background_color = color;
  }

  fn effective_scripting(&self) -> Scripting {
    let configured = if self.dom_scripting_enabled {
      Scripting::Enabled
    } else {
      Scripting::None
    };

    // Runtime toggles (typically sourced from `FASTR_*` env vars or per-render overrides) take
    // precedence so developers can simulate different environments without rebuilding.
    runtime::runtime_toggles()
      .config()
      .media
      .scripting
      .unwrap_or(configured)
  }

  fn dom_scripting_enabled(&self) -> bool {
    !matches!(self.effective_scripting(), Scripting::None)
  }

  fn media_context_for_media(
    &self,
    media_type: MediaType,
    width: f32,
    height: f32,
  ) -> MediaContext {
    let mut base = match media_type {
      MediaType::Print => MediaContext::print(width, height),
      _ => headless_chrome_screen_media_context(width, height),
    };
    if !matches!(media_type, MediaType::Print) {
      base = base.with_device_size(
        HEADLESS_CHROME_SCREEN_SIZE.width,
        HEADLESS_CHROME_SCREEN_SIZE.height,
      );
    }

    base
      .with_scripting(self.effective_scripting())
      .with_device_pixel_ratio(self.device_pixel_ratio)
      .with_env_overrides()
  }

  /// Create a simple placeholder pixmap indicating a render error.
  fn render_error_overlay(&self, width: u32, height: u32) -> Result<Pixmap> {
    let width = width.max(1);
    let height = height.max(1);
    let mut pixmap =
      new_pixmap(width, height).ok_or(Error::Render(RenderError::CanvasCreationFailed {
        width,
        height,
      }))?;
    // Light red background
    pixmap.fill(tiny_skia::Color::from_rgba8(255, 235, 238, 255));

    // Draw an "X" mark for visibility.
    let mut paint = tiny_skia::Paint::default();
    paint.set_color(tiny_skia::Color::from_rgba8(198, 40, 40, 255));
    paint.anti_alias = true;
    let mut stroke = tiny_skia::Stroke::default();
    stroke.width = 4.0;
    let inset = 12.0f32;
    let mut builder = tiny_skia::PathBuilder::new();
    builder.move_to(inset, inset);
    builder.line_to(width as f32 - inset, height as f32 - inset);
    builder.move_to(width as f32 - inset, inset);
    builder.line_to(inset, height as f32 - inset);
    if let Some(path) = builder.finish() {
      let _ = pixmap.stroke_path(
        &path,
        &paint,
        &stroke,
        tiny_skia::Transform::identity(),
        None,
      );
    }

    Ok(pixmap)
  }

  /// Extract the fragment identifier (without '#') for `:target` / `:target-within` matching.
  ///
  /// This must come from the *document* URL (navigation URL) rather than the effective base URL
  /// because `<base href>` is allowed to change relative URL resolution without affecting the
  /// document fragment identifier.
  fn current_target_fragment(&self) -> Option<String> {
    self
      .document_url
      .as_deref()
      .or_else(|| {
        self
          .resource_context
          .as_ref()
          .and_then(|ctx| ctx.document_url.as_deref())
      })
      .and_then(extract_fragment)
  }

  /// Fetch linked stylesheets and inject them into the document so they participate in cascade.
  fn inline_stylesheets(
    &self,
    html: &str,
    base_url: &str,
    media_type: MediaType,
    css_limit: Option<usize>,
    diagnostics: &mut RenderDiagnostics,
    deadline: Option<&RenderDeadline>,
    stats: Option<&mut RenderStatsRecorder>,
  ) -> std::result::Result<String, RenderError> {
    Self::inline_stylesheets_for_html_with_context_with_budget_with_toggles(
      self.fetcher.as_ref(),
      self.runtime_toggles.as_ref(),
      self.dom_scripting_enabled(),
      html,
      base_url,
      media_type,
      css_limit,
      self.resource_context.as_ref(),
      diagnostics,
      deadline,
      stats,
      StylesheetInlineBudget::default(),
    )
  }

  /// Fetch linked stylesheets using the renderer's fetcher and inject them into the HTML.
  ///
  /// `base_url` is treated as a document URL hint (used for referrer/origin policy). The effective
  /// base URL for resolving relative stylesheet hrefs is inferred from the document, honoring
  /// `<base href>` when present.
  pub fn inline_stylesheets_for_document(
    &self,
    html: &str,
    base_url: &str,
    media_type: MediaType,
    css_limit: Option<usize>,
    diagnostics: &mut RenderDiagnostics,
    deadline: Option<&RenderDeadline>,
  ) -> std::result::Result<String, RenderError> {
    let referrer_policy =
      crate::html::referrer_policy::extract_referrer_policy_from_html(html).unwrap_or_default();
    let csp = crate::html::content_security_policy::extract_csp_from_html(html);
    let base_hint = trim_ascii_whitespace(base_url);
    let document_url = if base_hint.is_empty() {
      None
    } else {
      Some(base_hint)
    };
    let mut resource_context = self.build_resource_context(document_url, None, referrer_policy);
    resource_context.csp = csp;
    let base_url = if let Some(base_hint) = document_url {
      crate::css::loader::infer_base_url(html, base_hint)
    } else {
      std::borrow::Cow::Borrowed("")
    };

    runtime::with_runtime_toggles(Arc::clone(&self.runtime_toggles), || {
      Self::inline_stylesheets_for_html_with_context_with_budget_with_toggles(
        self.fetcher.as_ref(),
        self.runtime_toggles.as_ref(),
        self.dom_scripting_enabled(),
        html,
        base_url.as_ref(),
        media_type,
        css_limit,
        Some(&resource_context),
        diagnostics,
        deadline,
        None,
        StylesheetInlineBudget::default(),
      )
    })
  }

  /// Fetch linked stylesheets using the renderer's fetcher with an explicit resource context.
  ///
  /// `base_url` is treated as a document URL hint; relative stylesheet hrefs are resolved against
  /// the inferred document base URL (honoring `<base href>`).
  pub fn inline_stylesheets_for_document_with_context(
    &self,
    html: &str,
    base_url: &str,
    media_type: MediaType,
    css_limit: Option<usize>,
    resource_context: Option<&ResourceContext>,
    diagnostics: &mut RenderDiagnostics,
    deadline: Option<&RenderDeadline>,
  ) -> std::result::Result<String, RenderError> {
    let base_hint = trim_ascii_whitespace(base_url);
    let base_url = if base_hint.is_empty() {
      std::borrow::Cow::Borrowed("")
    } else {
      crate::css::loader::infer_base_url(html, base_hint)
    };
    runtime::with_runtime_toggles(Arc::clone(&self.runtime_toggles), || {
      Self::inline_stylesheets_for_html_with_context_with_budget_with_toggles(
        self.fetcher.as_ref(),
        self.runtime_toggles.as_ref(),
        self.dom_scripting_enabled(),
        html,
        base_url.as_ref(),
        media_type,
        css_limit,
        resource_context,
        diagnostics,
        deadline,
        None,
        StylesheetInlineBudget::default(),
      )
    })
  }

