  fn find_node_by_id<'a>(node: &'a DomNode, id: &str) -> Option<&'a DomNode> {
    if node.get_attribute_ref("id") == Some(id) {
      return Some(node);
    }
    for child in node.children.iter() {
      if let Some(found) = find_node_by_id(child, id) {
        return Some(found);
      }
    }
    None
  }

  fn find_styled_node_by_id<'a>(node: &'a StyledNode, id: &str) -> Option<&'a StyledNode> {
    if node.node.get_attribute_ref("id") == Some(id) {
      return Some(node);
    }
    for child in node.children.iter() {
      if let Some(found) = find_styled_node_by_id(child, id) {
        return Some(found);
      }
    }
    None
  }

  fn rgba_at(buf: &[u8], stride_bytes: usize, x: u32, y: u32) -> [u8; 4] {
    let idx = (y as usize) * stride_bytes + (x as usize) * 4;
    [buf[idx], buf[idx + 1], buf[idx + 2], buf[idx + 3]]
  }

  #[test]
  fn prepared_document_paint_into_rgba_packed_stride_bytes() {
    let html = r#"<!doctype html>
<html>
  <head>
    <style>
      html, body { margin: 0; width: 100%; height: 100%; background: rgb(10, 20, 30); }
      #a { position: absolute; left: 0; top: 0; width: 8px; height: 8px; background: rgb(200, 0, 0); }
      #b { position: absolute; left: 8px; top: 0; width: 8px; height: 8px; background: rgb(0, 200, 0); }
      #c { position: absolute; left: 0; top: 8px; width: 8px; height: 8px; background: rgb(0, 0, 200); }
    </style>
  </head>
  <body>
    <div id="a"></div>
    <div id="b"></div>
    <div id="c"></div>
  </body>
</html>"#;

    let config = FastRenderConfig::default()
      .with_runtime_toggles(RuntimeToggles::default())
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled());
    let mut renderer = FastRender::with_config(config).expect("renderer");
    let prepared = renderer
      .prepare_html(
        html,
        RenderOptions::new()
          .with_viewport(16, 16)
          .with_device_pixel_ratio(1.0),
      )
      .expect("prepare")
      ;

    let stride = 16usize * 4;
    let mut buf = vec![0u8; stride * 16];
    prepared
      .paint_into_rgba(
        &mut buf,
        16,
        16,
        stride as u32,
        PreparedPaintOptions::default(),
      )
      .expect("paint_into_rgba");

    assert_eq!(rgba_at(&buf, stride, 1, 1), [200, 0, 0, 255]);
    assert_eq!(rgba_at(&buf, stride, 9, 1), [0, 200, 0, 255]);
    assert_eq!(rgba_at(&buf, stride, 1, 9), [0, 0, 200, 255]);
    assert_eq!(rgba_at(&buf, stride, 9, 9), [10, 20, 30, 255]);
  }

  #[test]
  fn prepared_document_paint_into_rgba_stride_mismatch_falls_back_to_copy() {
    let html = r#"<!doctype html>
<html>
  <head>
    <style>
      html, body { margin: 0; width: 100%; height: 100%; background: rgb(10, 20, 30); }
      #a { position: absolute; left: 0; top: 0; width: 8px; height: 8px; background: rgb(200, 0, 0); }
      #b { position: absolute; left: 8px; top: 0; width: 8px; height: 8px; background: rgb(0, 200, 0); }
      #c { position: absolute; left: 0; top: 8px; width: 8px; height: 8px; background: rgb(0, 0, 200); }
    </style>
  </head>
  <body>
    <div id="a"></div>
    <div id="b"></div>
    <div id="c"></div>
  </body>
</html>"#;

    let config = FastRenderConfig::default()
      .with_runtime_toggles(RuntimeToggles::default())
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled());
    let mut renderer = FastRender::with_config(config).expect("renderer");
    let prepared = renderer
      .prepare_html(
        html,
        RenderOptions::new()
          .with_viewport(16, 16)
          .with_device_pixel_ratio(1.0),
      )
      .expect("prepare")
      ;

    let stride = 16usize * 4 + 8;
    let mut buf = vec![0u8; stride * 16];
    prepared
      .paint_into_rgba(
        &mut buf,
        16,
        16,
        stride as u32,
        PreparedPaintOptions::default(),
      )
      .expect("paint_into_rgba (fallback)");

    assert_eq!(rgba_at(&buf, stride, 1, 1), [200, 0, 0, 255]);
    assert_eq!(rgba_at(&buf, stride, 9, 1), [0, 200, 0, 255]);
    assert_eq!(rgba_at(&buf, stride, 1, 9), [0, 0, 200, 255]);
    assert_eq!(rgba_at(&buf, stride, 9, 9), [10, 20, 30, 255]);

    // Padding bytes should be deterministically cleared.
    let row_bytes = 16usize * 4;
    for row in 0..16usize {
      let start = row * stride + row_bytes;
      assert!(
        buf[start..start + 8].iter().all(|&b| b == 0),
        "expected padding bytes to be zeroed"
      );
    }
  }

  #[test]
  fn captured_display_list_for_paint_requires_flag_and_value() {
    let some = Some(crate::paint::display_list::DisplayList::new());
    assert!(captured_display_list_for_paint(true, &some).is_some());
    assert!(captured_display_list_for_paint(false, &some).is_none());
    let none: Option<crate::paint::display_list::DisplayList> = None;
    assert!(captured_display_list_for_paint(true, &none).is_none());
  }

  #[test]
  fn render_pipeline_parses_html_with_scripting_enabled_semantics_by_default() {
    // `<noscript>` parsing semantics are controlled by html5ever's `scripting_enabled` flag:
    // - when disabled, child markup is parsed into DOM nodes
    // - when enabled, child markup is tokenized as raw text
    //
    // FastRender's public parse APIs default to scripting-disabled semantics, but the render
    // pipeline parses with scripting-enabled semantics by default to match Chrome baselines that
    // block script execution via CSP.
    let html = "<!doctype html><html><head><noscript><div id=noscript>fallback</div></noscript></head><body></body></html>";

    let config = FastRenderConfig::default()
      // Avoid inheriting ambient FASTR_* env vars in the test runner.
      .with_runtime_toggles(RuntimeToggles::default())
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled());
    let renderer = FastRender::with_config(config).expect("renderer");

    let dom = renderer.parse_html(html).expect("parse_html");
    assert!(
      find_node_by_id(&dom, "noscript").is_some(),
      "expected parse_html (default scripting disabled) to parse <noscript> children into DOM"
    );

    let dom_for_render = renderer
      .parse_html_for_render(html)
      .expect("parse_html_for_render");
    assert!(
      find_node_by_id(&dom_for_render, "noscript").is_none(),
      "expected render parsing (default scripting enabled) to avoid parsing <noscript> children into DOM"
    );

    let config = FastRenderConfig::default()
      .with_runtime_toggles(RuntimeToggles::default())
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled())
      .with_render_parse_scripting_enabled(false);
    let renderer =
      FastRender::with_config(config).expect("renderer (scripting disabled render parse)");
    let dom_for_render = renderer
      .parse_html_for_render(html)
      .expect("parse_html_for_render (scripting disabled)");
    assert!(
      find_node_by_id(&dom_for_render, "noscript").is_some(),
      "expected render parse toggle to enable scripting-disabled <noscript> parsing"
    );
  }

  #[test]
  fn render_pipeline_honors_autofocus_for_focus_pseudo_class_matching() {
    let html = r#"<!doctype html>
      <html>
        <head>
          <style>
            #skip, #target { box-shadow: none; }
            #skip:focus { box-shadow: 0 0 1px rgb(9, 9, 9); }
            #target:focus { box-shadow: 0 0 1px rgb(1, 2, 3); }
          </style>
        </head>
        <body>
          <input id="skip" autofocus disabled>
          <input id="target" autofocus>
        </body>
      </html>"#;

    let config = FastRenderConfig::default()
      // Avoid inheriting ambient FASTR_* env vars in the test runner.
      .with_runtime_toggles(RuntimeToggles::default())
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled());
    let mut renderer = FastRender::with_config(config).expect("renderer");
    let prepared = renderer
      .prepare_html(html, RenderOptions::new().with_viewport(200, 100))
      .expect("prepare_html");

    let skip = find_styled_node_by_id(prepared.styled_tree(), "skip").expect("skip node");
    let target = find_styled_node_by_id(prepared.styled_tree(), "target").expect("target node");

    assert_eq!(
      skip.styles.box_shadow.len(),
      0,
      "disabled autofocus controls should not match :focus"
    );
    assert_eq!(
      target.styles.box_shadow.len(),
      1,
      "expected autofocus to apply :focus styles to the first eligible element"
    );
  }

