  #[test]
  fn refresh_fragment_styles_does_not_clobber_boxless_block_fragments() {
    let mut inherited_old = ComputedStyle::default();
    inherited_old.background_color = Rgba::GREEN;
    let inherited_old = Arc::new(inherited_old);
    let mut inherited_new = ComputedStyle::default();
    inherited_new.background_color = Rgba::BLUE;
    let inherited_new = Arc::new(inherited_new);

    let mut child_style = ComputedStyle::default();
    child_style.background_color = Rgba::RED;
    child_style.display = crate::style::display::Display::TableHeaderGroup;
    let child_style = Arc::new(child_style);

    let mut root_box =
      BoxNode::new_block(inherited_old.clone(), FormattingContextType::Block, vec![]);
    root_box.styled_node_id = Some(1);
    let box_tree = BoxTree::new(root_box);
    let root_id = box_tree.root.id;

    let mut box_map = HashMap::new();
    super::collect_box_nodes(&box_tree.root, &mut box_map);

    let mut style_map = HashMap::new();
    style_map.insert(1 << super::STYLE_KEY_SHIFT, inherited_new.clone());

    let child_fragment = FragmentNode::new_with_style(
      Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
      FragmentContent::Block { box_id: None },
      vec![],
      child_style.clone(),
    );
    let mut root_fragment = FragmentNode::new_block_with_id(
      Rect::from_xywh(0.0, 0.0, 10.0, 10.0),
      root_id,
      vec![child_fragment],
    );
    root_fragment.style = Some(inherited_old);

    super::refresh_fragment_styles(&mut root_fragment, &box_map, &style_map, None, false);

    assert!(
      Arc::ptr_eq(
        root_fragment.style.as_ref().expect("root style refreshed"),
        &inherited_new
      ),
      "expected root style to refresh from style map"
    );

    let child = &root_fragment.children[0];
    let child_style = child.style.as_ref().expect("child style preserved");
    assert_eq!(
      child_style.background_color,
      Rgba::RED,
      "expected boxless block fragment style to not be overwritten by inherited styles"
    );
    assert!(
      matches!(
        child_style.display,
        crate::style::display::Display::TableHeaderGroup
      ),
      "expected boxless block fragment display to remain intact"
    );
  }

  #[test]
  fn refresh_fragment_styles_reapplies_table_wrapper_and_grid_style_splitting() {
    let old_style = Arc::new(ComputedStyle::default());

    let mut base_style = ComputedStyle::default();
    base_style.display = crate::style::display::Display::Table;
    base_style.background_color = Rgba::RED;
    base_style.opacity = 0.5;
    base_style.mix_blend_mode = crate::style::types::MixBlendMode::Multiply;
    base_style.isolation = crate::style::types::Isolation::Isolate;
    let base_style = Arc::new(base_style);

    let mut table_box = BoxNode::new_block(old_style.clone(), FormattingContextType::Table, vec![]);
    table_box.styled_node_id = Some(1);
    let box_tree = BoxTree::new(table_box);
    let table_id = box_tree.root.id;

    let mut box_map = HashMap::new();
    super::collect_box_nodes(&box_tree.root, &mut box_map);

    let mut style_map = HashMap::new();
    style_map.insert(1 << super::STYLE_KEY_SHIFT, base_style.clone());

    let mut caption_style = ComputedStyle::default();
    caption_style.display = crate::style::display::Display::TableCaption;
    let caption_style = Arc::new(caption_style);

    let caption = FragmentNode::new_with_style(
      Rect::from_xywh(0.0, 0.0, 10.0, 10.0),
      FragmentContent::Block { box_id: None },
      vec![],
      caption_style,
    );

    let grid = FragmentNode::new_with_style(
      Rect::from_xywh(0.0, 10.0, 10.0, 10.0),
      FragmentContent::Block {
        box_id: Some(table_id),
      },
      vec![],
      Arc::new(ComputedStyle::default()),
    );

    let mut wrapper = FragmentNode::new_with_style(
      Rect::from_xywh(0.0, 0.0, 10.0, 20.0),
      FragmentContent::Block {
        box_id: Some(table_id),
      },
      vec![caption, grid],
      Arc::new(ComputedStyle::default()),
    );

    super::refresh_fragment_styles(&mut wrapper, &box_map, &style_map, None, false);

    let wrapper_style = wrapper.style.as_ref().expect("wrapper style refreshed");
    assert_eq!(
      wrapper_style.background_color,
      Rgba::TRANSPARENT,
      "expected table wrapper to reset backgrounds"
    );
    assert!((wrapper_style.opacity - 0.5).abs() < f32::EPSILON);
    assert_eq!(
      wrapper_style.mix_blend_mode,
      crate::style::types::MixBlendMode::Multiply
    );
    assert_eq!(
      wrapper_style.isolation,
      crate::style::types::Isolation::Isolate
    );

    let grid_style = wrapper.children[1]
      .style
      .as_ref()
      .expect("grid style refreshed");
    assert_eq!(
      grid_style.background_color,
      Rgba::RED,
      "expected table grid to keep author background"
    );
    assert!(
      (grid_style.opacity - 1.0).abs() < f32::EPSILON,
      "expected table grid to clear opacity when wrapper exists"
    );
    assert_eq!(
      grid_style.mix_blend_mode,
      crate::style::types::MixBlendMode::Normal
    );
    assert_eq!(grid_style.isolation, crate::style::types::Isolation::Auto);
  }

  #[test]
  fn refresh_fragment_styles_preserves_table_decoration_display_and_border_stripping() {
    let old_style = Arc::new(ComputedStyle::default());

    let mut table_box = BoxNode::new_block(old_style.clone(), FormattingContextType::Table, vec![]);
    table_box.styled_node_id = Some(1);
    let mut row_group_box =
      BoxNode::new_block(old_style.clone(), FormattingContextType::Block, vec![]);
    row_group_box.styled_node_id = Some(2);
    table_box.children.push(row_group_box);
    let box_tree = BoxTree::new(table_box);
    let row_group_id = box_tree.root.children[0].id;

    let mut box_map = HashMap::new();
    super::collect_box_nodes(&box_tree.root, &mut box_map);

    let mut refreshed = ComputedStyle::default();
    refreshed.display = crate::style::display::Display::TableHeaderGroup;
    refreshed.background_color = Rgba::RED;
    refreshed.border_top_style = crate::style::types::BorderStyle::Solid;
    refreshed.border_top_width = Length::px(4.0);
    let refreshed = Arc::new(refreshed);

    let mut style_map = HashMap::new();
    style_map.insert(2 << super::STYLE_KEY_SHIFT, refreshed);

    let mut stripped = ComputedStyle::default();
    stripped.display = crate::style::display::Display::TableRowGroup;
    stripped.background_color = Rgba::GREEN;
    stripped.border_top_style = crate::style::types::BorderStyle::None;
    stripped.border_top_width = Length::px(0.0);
    stripped.border_right_style = crate::style::types::BorderStyle::None;
    stripped.border_right_width = Length::px(0.0);
    stripped.border_bottom_style = crate::style::types::BorderStyle::None;
    stripped.border_bottom_width = Length::px(0.0);
    stripped.border_left_style = crate::style::types::BorderStyle::None;
    stripped.border_left_width = Length::px(0.0);
    let stripped = Arc::new(stripped);

    let mut fragment = FragmentNode::new_with_style(
      Rect::from_xywh(0.0, 0.0, 10.0, 10.0),
      FragmentContent::Block {
        box_id: Some(row_group_id),
      },
      vec![],
      stripped,
    );

    super::refresh_fragment_styles(&mut fragment, &box_map, &style_map, None, false);

    let style = fragment.style.as_ref().expect("style refreshed");
    assert_eq!(
      style.background_color,
      Rgba::RED,
      "expected table decoration fragment to pick up refreshed background"
    );
    assert!(
      matches!(style.display, crate::style::display::Display::TableRowGroup),
      "expected effective display override to be preserved"
    );
    assert!(
      matches!(
        style.border_top_style,
        crate::style::types::BorderStyle::None
      ),
      "expected table decoration borders to remain stripped"
    );
    assert!(style.border_top_width.to_px().abs() < f32::EPSILON);
  }

  #[test]
  fn refresh_fragment_styles_refreshes_form_control_pseudo_styles() {
    let base_style = Arc::new(ComputedStyle::default());
    let old_placeholder = Arc::new(ComputedStyle::default());
    let mut new_placeholder = ComputedStyle::default();
    new_placeholder.font_size = 22.0;
    let new_placeholder = Arc::new(new_placeholder);

    let control = ReplacedType::FormControl(crate::tree::box_tree::FormControl {
      control: FormControlKind::Text {
        value: String::new(),
        placeholder: Some("hint".to_string()),
        placeholder_style: Some(old_placeholder.clone()),
        size_attr: None,
        kind: TextControlKind::Plain,
        caret: 0,
        caret_affinity: crate::text::caret::CaretAffinity::Downstream,
        selection: None,
      },
      appearance: crate::style::types::Appearance::Auto,
      placeholder_style: Some(old_placeholder.clone()),
      slider_thumb_style: None,
      slider_track_style: None,
      progress_bar_style: None,
      progress_value_style: None,
      meter_bar_style: None,
      meter_optimum_value_style: None,
      meter_suboptimum_value_style: None,
      meter_even_less_good_value_style: None,
      file_selector_button_style: None,
      disabled: false,
      focused: false,
      focus_visible: false,
      required: false,
      invalid: false,
      ime_preedit: None,
    });

    let mut input = BoxNode::new_replaced(base_style.clone(), control.clone(), None, None);
    input.styled_node_id = Some(1);
    let mut root = BoxNode::new_block(
      base_style.clone(),
      FormattingContextType::Block,
      vec![input],
    );
    root.styled_node_id = Some(1);
    let box_tree = BoxTree::new(root);
    let input_id = box_tree.root.children[0].id;

    let mut box_map = HashMap::new();
    super::collect_box_nodes(&box_tree.root, &mut box_map);

    let base_key = 1 << super::STYLE_KEY_SHIFT;
    let mut style_map = HashMap::new();
    style_map.insert(base_key, base_style);
    style_map.insert(
      base_key | super::STYLE_KEY_PLACEHOLDER,
      new_placeholder.clone(),
    );

    let mut fragment = FragmentNode::new_with_style(
      Rect::from_xywh(0.0, 0.0, 10.0, 10.0),
      FragmentContent::Replaced {
        replaced_type: control,
        box_id: Some(input_id),
      },
      vec![],
      Arc::new(ComputedStyle::default()),
    );

    super::refresh_fragment_styles(&mut fragment, &box_map, &style_map, None, false);

    let FragmentContent::Replaced { replaced_type, .. } = &fragment.content else {
      panic!("expected replaced fragment");
    };
    let ReplacedType::FormControl(control) = replaced_type else {
      panic!("expected form control replaced type");
    };
    match &control.control {
      FormControlKind::Text {
        placeholder_style, ..
      } => {
        assert!(
          placeholder_style
            .as_ref()
            .is_some_and(|style| Arc::ptr_eq(style, &new_placeholder)),
          "expected placeholder pseudo styles to refresh"
        );
      }
      other => panic!("expected text control, got {other:?}"),
    }
    assert!(
      control
        .placeholder_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &new_placeholder)),
      "expected top-level form control placeholder style to refresh"
    );
  }

  #[test]
  fn refresh_box_tree_styles_updates_styles_including_pseudos_and_footnotes() {
    let old_style = Arc::new(ComputedStyle::default());

    let mut new_root = ComputedStyle::default();
    new_root.font_size = 11.0;
    let new_root = Arc::new(new_root);

    let mut new_before = ComputedStyle::default();
    new_before.font_size = 12.0;
    let new_before = Arc::new(new_before);

    let mut new_marker = ComputedStyle::default();
    new_marker.font_size = 13.0;
    let new_marker = Arc::new(new_marker);

    let mut new_call = ComputedStyle::default();
    new_call.font_size = 14.0;
    let new_call = Arc::new(new_call);

    let mut new_body = ComputedStyle::default();
    new_body.font_size = 15.0;
    let new_body = Arc::new(new_body);

    let mut new_first_line = ComputedStyle::default();
    new_first_line.color = Rgba::RED;
    let new_first_line = Arc::new(new_first_line);

    let mut new_first_letter = ComputedStyle::default();
    new_first_letter.color = Rgba::BLUE;
    let new_first_letter = Arc::new(new_first_letter);

    let mut before = BoxNode::new_inline(old_style.clone(), vec![]);
    before.styled_node_id = Some(1);
    before.generated_pseudo = Some(crate::tree::box_tree::GeneratedPseudoElement::Before);

    let mut marker = BoxNode::new_marker(old_style.clone(), MarkerContent::Text("*".to_string()));
    marker.styled_node_id = Some(1);

    let mut body = BoxNode::new_block(old_style.clone(), FormattingContextType::Block, vec![]);
    body.styled_node_id = Some(2);

    let mut call = BoxNode::new_inline(old_style.clone(), vec![]);
    call.styled_node_id = Some(2);
    call.generated_pseudo = Some(crate::tree::box_tree::GeneratedPseudoElement::FootnoteCall);
    call.footnote_body = Some(Box::new(body));

    let mut root = BoxNode::new_block(
      old_style,
      FormattingContextType::Block,
      vec![before, marker, call],
    );
    root.styled_node_id = Some(1);
    let mut box_tree = BoxTree::new(root);

    let mut style_map = HashMap::new();
    let base1 = 1 << super::STYLE_KEY_SHIFT;
    let base2 = 2 << super::STYLE_KEY_SHIFT;
    style_map.insert(base1, new_root.clone());
    style_map.insert(base1 | super::STYLE_KEY_BEFORE, new_before.clone());
    style_map.insert(base1 | super::STYLE_KEY_MARKER, new_marker.clone());
    style_map.insert(base1 | super::STYLE_KEY_FIRST_LINE, new_first_line.clone());
    style_map.insert(base1 | super::STYLE_KEY_FIRST_LETTER, new_first_letter.clone());
    style_map.insert(base2, new_body.clone());
    style_map.insert(base2 | super::STYLE_KEY_FOOTNOTE_CALL, new_call.clone());

    super::refresh_box_tree_styles(&mut box_tree.root, &style_map);

    assert!(
      Arc::ptr_eq(&box_tree.root.style, &new_root),
      "expected root style to refresh"
    );
    assert!(
      box_tree
        .root
        .first_line_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &new_first_line)),
      "expected ::first-line style to refresh"
    );
    assert!(
      box_tree
        .root
        .first_letter_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &new_first_letter)),
      "expected ::first-letter style to refresh"
    );

    assert!(
      Arc::ptr_eq(&box_tree.root.children[0].style, &new_before),
      "expected ::before box style to refresh"
    );
    assert!(
      Arc::ptr_eq(&box_tree.root.children[1].style, &new_marker),
      "expected marker box style to refresh"
    );
    assert!(
      Arc::ptr_eq(&box_tree.root.children[2].style, &new_call),
      "expected ::footnote-call box style to refresh"
    );
    assert!(
      box_tree.root.children[2]
        .footnote_body
        .as_deref()
        .is_some_and(|node| Arc::ptr_eq(&node.style, &new_body)),
      "expected footnote body styles to refresh"
    );
  }

  #[test]
  fn refresh_fragment_tree_styles_visits_additional_fragments() {
    let old_style = Arc::new(ComputedStyle::default());

    let mut new_root = ComputedStyle::default();
    new_root.font_size = 12.0;
    let new_root = Arc::new(new_root);

    let mut new_child = ComputedStyle::default();
    new_child.font_size = 20.0;
    let new_child = Arc::new(new_child);

    let mut child = BoxNode::new_block(old_style.clone(), FormattingContextType::Block, vec![]);
    child.styled_node_id = Some(2);
    let mut root = BoxNode::new_block(old_style.clone(), FormattingContextType::Block, vec![child]);
    root.styled_node_id = Some(1);
    let tree = BoxTree::new(root);
    let root_id = tree.root.id;
    let child_id = tree.root.children[0].id;

    let mut box_map = HashMap::new();
    super::collect_box_nodes(&tree.root, &mut box_map);

    let mut style_map = HashMap::new();
    style_map.insert(1 << super::STYLE_KEY_SHIFT, new_root.clone());
    style_map.insert(2 << super::STYLE_KEY_SHIFT, new_child.clone());

    let mut fragment_tree = FragmentTree::with_viewport(
      FragmentNode::new_block_with_id(Rect::from_xywh(0.0, 0.0, 1.0, 1.0), root_id, vec![]),
      Size::new(100.0, 100.0),
    );
    fragment_tree.root.style = Some(old_style.clone());

    let mut second =
      FragmentNode::new_block_with_id(Rect::from_xywh(0.0, 0.0, 1.0, 1.0), child_id, vec![]);
    second.style = Some(old_style);
    fragment_tree.additional_fragments.push(second);

    super::refresh_fragment_tree_styles(&mut fragment_tree, &box_map, &style_map);

    assert!(
      Arc::ptr_eq(fragment_tree.root.style.as_ref().unwrap(), &new_root),
      "expected root fragment style to refresh"
    );
    assert!(
      Arc::ptr_eq(
        fragment_tree.additional_fragments[0]
          .style
          .as_ref()
          .unwrap(),
        &new_child
      ),
      "expected additional root fragments to refresh styles"
    );
  }

  #[test]
  fn refresh_fragment_tree_styles_refreshes_appearance_none_form_control_pseudo_styles() {
    let base_style = Arc::new(ComputedStyle::default());

    let old_placeholder = Arc::new(ComputedStyle::default());
    let mut new_placeholder = ComputedStyle::default();
    new_placeholder.font_size = 22.0;
    let new_placeholder = Arc::new(new_placeholder);

    let old_file_button = Arc::new(ComputedStyle::default());
    let mut new_file_button = ComputedStyle::default();
    new_file_button.font_size = 18.0;
    let new_file_button = Arc::new(new_file_button);

    let mut text_box = BoxNode::new_block(base_style.clone(), FormattingContextType::Block, vec![]);
    text_box.styled_node_id = Some(1);

    let mut file_box = BoxNode::new_block(base_style.clone(), FormattingContextType::Block, vec![]);
    file_box.styled_node_id = Some(2);

    let mut checkbox_box =
      BoxNode::new_block(base_style.clone(), FormattingContextType::Block, vec![]);
    checkbox_box.styled_node_id = Some(3);

    let mut root = BoxNode::new_block(
      base_style.clone(),
      FormattingContextType::Block,
      vec![text_box, file_box, checkbox_box],
    );
    root.styled_node_id = Some(4);
    let box_tree = BoxTree::new(root);
    let text_box_id = box_tree.root.children[0].id;
    let file_box_id = box_tree.root.children[1].id;
    let checkbox_box_id = box_tree.root.children[2].id;

    let mut box_map = HashMap::new();
    super::collect_box_nodes(&box_tree.root, &mut box_map);

    let text_control = Arc::new(crate::tree::box_tree::FormControl {
      control: FormControlKind::Text {
        value: String::new(),
        placeholder: Some("hint".to_string()),
        placeholder_style: Some(old_placeholder.clone()),
        size_attr: None,
        kind: TextControlKind::Plain,
        caret: 0,
        caret_affinity: crate::text::caret::CaretAffinity::Downstream,
        selection: None,
      },
      appearance: crate::style::types::Appearance::None,
      placeholder_style: Some(old_placeholder.clone()),
      slider_thumb_style: None,
      slider_track_style: None,
      progress_bar_style: None,
      progress_value_style: None,
      meter_bar_style: None,
      meter_optimum_value_style: None,
      meter_suboptimum_value_style: None,
      meter_even_less_good_value_style: None,
      file_selector_button_style: None,
      disabled: false,
      focused: false,
      focus_visible: false,
      required: false,
      invalid: false,
      ime_preedit: None,
    });

    let file_control = Arc::new(crate::tree::box_tree::FormControl {
      control: FormControlKind::File { value: None },
      appearance: crate::style::types::Appearance::None,
      placeholder_style: None,
      slider_thumb_style: None,
      slider_track_style: None,
      progress_bar_style: None,
      progress_value_style: None,
      meter_bar_style: None,
      meter_optimum_value_style: None,
      meter_suboptimum_value_style: None,
      meter_even_less_good_value_style: None,
      file_selector_button_style: Some(old_file_button.clone()),
      disabled: false,
      focused: false,
      focus_visible: false,
      required: false,
      invalid: false,
      ime_preedit: None,
    });

    let checkbox_control = Arc::new(crate::tree::box_tree::FormControl {
      control: FormControlKind::Checkbox {
        is_radio: false,
        checked: false,
        indeterminate: false,
      },
      appearance: crate::style::types::Appearance::None,
      placeholder_style: None,
      slider_thumb_style: None,
      slider_track_style: None,
      progress_bar_style: None,
      progress_value_style: None,
      meter_bar_style: None,
      meter_optimum_value_style: None,
      meter_suboptimum_value_style: None,
      meter_even_less_good_value_style: None,
      file_selector_button_style: None,
      disabled: false,
      focused: false,
      focus_visible: false,
      required: false,
      invalid: false,
      ime_preedit: None,
    });

    let mut appearance_map: HashMap<usize, Arc<crate::tree::box_tree::FormControl>> = HashMap::new();
    appearance_map.insert(text_box_id, Arc::clone(&text_control));
    appearance_map.insert(file_box_id, Arc::clone(&file_control));
    appearance_map.insert(checkbox_box_id, Arc::clone(&checkbox_control));

    let mut fragment_tree = FragmentTree::with_viewport(
      FragmentNode::new_block_with_id(
        Rect::from_xywh(0.0, 0.0, 1.0, 1.0),
        box_tree.root.id,
        vec![],
      ),
      Size::new(100.0, 100.0),
    );
    fragment_tree.root.style = Some(base_style.clone());
    fragment_tree.appearance_none_form_controls = Some(Arc::new(appearance_map));
    let previous_map = fragment_tree
      .appearance_none_form_controls
      .as_ref()
      .expect("appearance map set")
      .clone();

    let mut style_map = HashMap::new();
    style_map.insert(1 << super::STYLE_KEY_SHIFT, base_style.clone());
    style_map.insert(
      (1 << super::STYLE_KEY_SHIFT) | super::STYLE_KEY_PLACEHOLDER,
      new_placeholder.clone(),
    );
    style_map.insert(2 << super::STYLE_KEY_SHIFT, base_style.clone());
    style_map.insert(
      (2 << super::STYLE_KEY_SHIFT) | super::STYLE_KEY_FILE_SELECTOR_BUTTON,
      new_file_button.clone(),
    );
    style_map.insert(3 << super::STYLE_KEY_SHIFT, base_style.clone());
    style_map.insert(4 << super::STYLE_KEY_SHIFT, base_style);

    super::refresh_fragment_tree_styles(&mut fragment_tree, &box_map, &style_map);

    let refreshed_map = fragment_tree
      .appearance_none_form_controls
      .as_ref()
      .expect("appearance map preserved");
    assert!(
      !Arc::ptr_eq(refreshed_map, &previous_map),
      "expected refreshed map to be replaced when control pseudo styles change"
    );

    let refreshed_text = refreshed_map
      .get(&text_box_id)
      .expect("text control entry");
    assert!(
      !Arc::ptr_eq(refreshed_text, &text_control),
      "expected changed control to be replaced"
    );
    match &refreshed_text.control {
      FormControlKind::Text {
        placeholder_style, ..
      } => assert!(
        placeholder_style
          .as_ref()
          .is_some_and(|style| Arc::ptr_eq(style, &new_placeholder)),
        "expected text control ::placeholder style to refresh"
      ),
      other => panic!("expected text control, got {other:?}"),
    }
    assert!(
      refreshed_text
        .placeholder_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &new_placeholder)),
      "expected top-level placeholder style to refresh"
    );

    let refreshed_file = refreshed_map
      .get(&file_box_id)
      .expect("file control entry");
    assert!(
      !Arc::ptr_eq(refreshed_file, &file_control),
      "expected changed control to be replaced"
    );
    assert!(
      refreshed_file
        .file_selector_button_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &new_file_button)),
      "expected ::file-selector-button style to refresh"
    );

    let refreshed_checkbox = refreshed_map
      .get(&checkbox_box_id)
      .expect("checkbox control entry");
    assert!(
      Arc::ptr_eq(refreshed_checkbox, &checkbox_control),
      "expected unchanged control to preserve original Arc"
    );

    // Ensure previously stored arcs were not mutated.
    match &text_control.control {
      FormControlKind::Text {
        placeholder_style, ..
      } => assert!(
        placeholder_style
          .as_ref()
          .is_some_and(|style| Arc::ptr_eq(style, &old_placeholder)),
        "expected original text control placeholder style to remain unchanged"
      ),
      other => panic!("expected text control, got {other:?}"),
    }
    assert!(
      text_control
        .placeholder_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &old_placeholder)),
      "expected original top-level placeholder style to remain unchanged"
    );
    assert!(
      file_control
        .file_selector_button_style
        .as_ref()
        .is_some_and(|style| Arc::ptr_eq(style, &old_file_button)),
      "expected original file selector button style to remain unchanged"
    );
  }

