  #[test]
  fn layout_image_cache_configuration_changes_reset_cached_formatting_contexts() {
    let mut renderer = FastRender::new().expect("renderer");
    renderer.set_base_url("https://example.com/a/");

    let style = Arc::new(ComputedStyle::default());
    let node = BoxNode::new_block(style, FormattingContextType::Block, vec![]);
    let constraints = LayoutConstraints::definite(32.0, 32.0);

    renderer
      .layout_engine()
      .layout_subtree(&node, &constraints)
      .expect("initial layout");
    assert!(
      renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected a cached block formatting context after layout"
    );

    renderer.set_base_url("https://example.com/b/");
    assert!(
      !renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected base url updates to reset cached formatting contexts"
    );

    renderer
      .layout_engine()
      .layout_subtree(&node, &constraints)
      .expect("layout after base url update");
    assert_eq!(
      renderer.layout_engine().image_cache().base_url(),
      Some("https://example.com/b/".to_string())
    );
    assert!(
      renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected cached formatting context to be rebuilt after base url update"
    );

    renderer.clear_base_url();
    assert!(
      !renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected clearing the base url to reset cached formatting contexts"
    );
    assert_eq!(renderer.layout_engine().image_cache().base_url(), None);

    renderer
      .layout_engine()
      .layout_subtree(&node, &constraints)
      .expect("layout after base url cleared");
    assert!(
      renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected cached formatting contexts to be initialized again after layout"
    );

    let diagnostics = Arc::new(Mutex::new(RenderDiagnostics::default()));
    renderer.set_diagnostics_sink(Some(Arc::clone(&diagnostics)));
    assert!(
      !renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected diagnostics sink updates to reset cached formatting contexts"
    );

    renderer
      .layout_engine()
      .layout_subtree(&node, &constraints)
      .expect("layout after diagnostics sink update");
    assert!(
      renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected cached formatting contexts to be rebuilt after diagnostics sink update"
    );

    let context = Some(renderer.build_resource_context(
      Some("https://example.com/"),
      None,
      ReferrerPolicy::default(),
    ));
    let (prev_self, prev_image, prev_layout_image, prev_font) =
      renderer.push_resource_context(context);
    assert!(
      !renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected resource context pushes to reset cached formatting contexts"
    );

    renderer
      .layout_engine()
      .layout_subtree(&node, &constraints)
      .expect("layout after resource context push");
    assert!(
      renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected cached formatting contexts to be rebuilt after resource context push"
    );

    renderer.pop_resource_context(prev_self, prev_image, prev_layout_image, prev_font);
    assert!(
      !renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected resource context pops to reset cached formatting contexts"
    );
  }

  #[test]
  fn layout_shape_outside_image_masks_observe_updated_base_url() {
    use image::codecs::png::PngEncoder;
    use image::ColorType;
    use image::ImageEncoder;
    use image::RgbaImage;

    #[derive(Clone)]
    struct RecordingFetcher {
      requests: Arc<Mutex<Vec<String>>>,
      response: Arc<Vec<u8>>,
    }

    impl crate::resource::ResourceFetcher for RecordingFetcher {
      fn fetch(&self, url: &str) -> Result<FetchedResource> {
        self
          .requests
          .lock()
          .unwrap_or_else(|poisoned| poisoned.into_inner())
          .push(url.to_string());
        Ok(FetchedResource::new(
          (*self.response).clone(),
          Some("image/png".to_string()),
        ))
      }
    }

    let img = RgbaImage::from_raw(1, 1, vec![0, 0, 0, 255]).expect("rgba image");
    let mut png = Vec::new();
    PngEncoder::new(&mut png)
      .write_image(&img, 1, 1, ColorType::Rgba8.into())
      .expect("encode png");
    let requests = Arc::new(Mutex::new(Vec::new()));
    let fetcher = Arc::new(RecordingFetcher {
      requests: Arc::clone(&requests),
      response: Arc::new(png),
    });

    let mut renderer = FastRender::with_config_and_fetcher(
      FastRenderConfig::default(),
      Some(fetcher.clone() as Arc<dyn crate::resource::ResourceFetcher>),
    )
    .expect("renderer");

    let mut root_style = ComputedStyle::default();
    root_style.display = crate::style::display::Display::Block;
    let mut float_style = ComputedStyle::default();
    float_style.display = crate::style::display::Display::Block;
    float_style.float = crate::style::float::Float::Left;
    float_style.shape_outside = crate::style::types::ShapeOutside::Image(BackgroundImage::Url(
      crate::style::types::BackgroundImageUrl::new("mask.png".to_string()),
    ));
    let float_node =
      BoxNode::new_block(Arc::new(float_style), FormattingContextType::Block, vec![]);
    let root_node = BoxNode::new_block(
      Arc::new(root_style),
      FormattingContextType::Block,
      vec![float_node],
    );
    let constraints = LayoutConstraints::definite(200.0, 200.0);

    renderer.set_base_url("https://example.com/a/");
    renderer
      .layout_engine()
      .layout_subtree(&root_node, &constraints)
      .expect("layout with base url A");
    assert!(
      renderer
        .layout_engine()
        .cached_context_is_initialized(FormattingContextType::Block),
      "expected block formatting context to be cached after layout"
    );

    renderer.set_base_url("https://example.com/b/");
    renderer
      .layout_engine()
      .layout_subtree(&root_node, &constraints)
      .expect("layout with base url B");

    let reqs = requests
      .lock()
      .unwrap_or_else(|poisoned| poisoned.into_inner())
      .clone();
    assert!(
      reqs
        .iter()
        .any(|url| url == "https://example.com/a/mask.png"),
      "expected initial shape-outside mask to resolve against base url A; got {reqs:?}"
    );
    assert!(
      reqs
        .iter()
        .any(|url| url == "https://example.com/b/mask.png"),
      "expected updated shape-outside mask to resolve against base url B; got {reqs:?}"
    );
  }

  #[test]
  #[cfg(feature = "direct_network")]
  fn inline_stylesheet_http_403_records_fetch_error_status_and_url() {
    use std::io::{Read, Write};
    use std::net::TcpListener;
    use std::time::Duration;

    let listener = match TcpListener::bind("127.0.0.1:0") {
      Ok(listener) => listener,
      Err(err)
        if matches!(
          err.kind(),
          std::io::ErrorKind::PermissionDenied | std::io::ErrorKind::AddrNotAvailable
        ) =>
      {
        eprintln!("skipping inline_stylesheet_http_403_records_fetch_error_status_and_url: cannot bind localhost: {err}");
        return;
      }
      Err(err) => panic!("bind localhost: {err}"),
    };
    let addr = listener.local_addr().expect("listener addr");
    let css_url = format!("http://{addr}/blocked.css");

    let server = std::thread::spawn(move || {
      let (mut stream, _) = listener.accept().expect("accept");
      let _ = stream.set_read_timeout(Some(Duration::from_secs(1)));
      let mut buf = [0u8; 1024];
      let _ = stream.read(&mut buf);

      let body = "<html>Forbidden</html>";
      let response = format!(
        "HTTP/1.1 403 Forbidden\r\nContent-Type: text/html; charset=utf-8\r\nContent-Length: {}\r\nConnection: close\r\n\r\n{}",
        body.len(),
        body
      );
      stream
        .write_all(response.as_bytes())
        .expect("write response");
      let _ = stream.flush();
    });

    let html = format!(
      "<!doctype html><html><head><link rel=\"stylesheet\" href=\"{css_url}\"></head><body>ok</body></html>"
    );
    let fetcher = HttpFetcher::new();
    let mut diagnostics = RenderDiagnostics::default();
    let output = FastRender::inline_stylesheets_for_html(
      &fetcher,
      &html,
      "http://example.com/",
      MediaType::Screen,
      None,
      &mut diagnostics,
      None,
    )
    .expect("inline stylesheets");

    // The stylesheet fetch should fail and be recorded, but inlining remains best-effort.
    assert!(!output.is_empty());
    let entry = diagnostics
      .fetch_errors
      .iter()
      .find(|e| e.kind == ResourceKind::Stylesheet && e.url == css_url)
      .expect("stylesheet fetch error");
    assert_eq!(entry.status, Some(403));
    assert_eq!(entry.final_url.as_deref(), Some(css_url.as_str()));

    server.join().unwrap();
  }

  #[derive(Clone, Default)]
  struct DnsFailureFetcher;

  impl ResourceFetcher for DnsFailureFetcher {
    fn fetch(&self, url: &str) -> crate::error::Result<FetchedResource> {
      let cause = io::Error::new(
        io::ErrorKind::Other,
        "dns error: failed to lookup address information",
      );
      Err(Error::Resource(
        ResourceError::new(
          url.to_string(),
          format!("error sending request for url ({url})"),
        )
        .with_final_url(url.to_string())
        .with_source(cause),
      ))
    }
  }

  #[derive(Clone, Default)]
  struct Http404Fetcher;

  impl ResourceFetcher for Http404Fetcher {
    fn fetch(&self, url: &str) -> crate::error::Result<FetchedResource> {
      let mut resource = FetchedResource::new(Vec::new(), Some("text/css".to_string()));
      resource.status = Some(404);
      resource.final_url = Some(url.to_string());
      Ok(resource)
    }
  }

