  #[test]
  fn document_fetch_propagates_non_timeout_render_errors_from_fetcher() {
    let config = FastRenderConfig::default()
      .with_runtime_toggles(RuntimeToggles::default())
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled())
      .with_base_url("https://example.com/page.html");
    let mut renderer =
      FastRender::with_config_and_fetcher(config, Some(Arc::new(RenderMemoryBudgetFetcher)))
        .expect("renderer");

    let options = RenderOptions::new().allow_partial(true);

    let err = match renderer.prepare_url("https://example.com/", options.clone()) {
      Ok(_) => panic!("expected render error from document fetch"),
      Err(err) => err,
    };
    assert!(
      matches!(
        err,
        Error::Render(RenderError::StageMemoryBudgetExceeded {
          stage: RenderStage::DomParse,
          rss_bytes: 2,
          budget_bytes: 1
        })
      ),
      "expected stage memory budget error, got {err:?}"
    );

    let err = match renderer.prepare_http_request(
      "https://example.com/",
      "GET",
      &[],
      None,
      options.clone(),
    ) {
      Ok(_) => panic!("expected render error from document fetch"),
      Err(err) => err,
    };
    assert!(
      matches!(
        err,
        Error::Render(RenderError::StageMemoryBudgetExceeded {
          stage: RenderStage::DomParse,
          rss_bytes: 2,
          budget_bytes: 1
        })
      ),
      "expected stage memory budget error, got {err:?}"
    );

    let err = match renderer.render_url_with_options("https://example.com/", options) {
      Ok(_) => panic!("expected render error from document fetch"),
      Err(err) => err,
    };
    assert!(
      matches!(
        err,
        Error::Render(RenderError::StageMemoryBudgetExceeded {
          stage: RenderStage::DomParse,
          rss_bytes: 2,
          budget_bytes: 1
        })
      ),
      "expected stage memory budget error, got {err:?}"
    );
  }

  #[test]
  fn css_import_fetcher_network_error_returns_empty_without_diagnostics() {
    let sink = Arc::new(Mutex::new(RenderDiagnostics::default()));
    let ctx = ResourceContext {
      document_url: Some("https://example.com/".to_string()),
      referrer_policy: Default::default(),
      policy: ResourceAccessPolicy::default(),
      csp: None,
      diagnostics: Some(SharedRenderDiagnostics {
        inner: Arc::clone(&sink),
      }),
      iframe_depth_remaining: None,
      iframe_embedder: None,
    };
    let loader = CssImportFetcher::new(
      Some("https://example.com/".to_string()),
      None,
      Arc::new(DnsFailureFetcher),
      Some(ctx),
      None,
      ReferrerPolicy::default(),
    );

    let css = loader
      .load("https://sf-saas.cdn-apple.com/2.4.0-beta.0/animations/all.css")
      .expect("dns failure should return empty stylesheet");
    assert!(css.is_empty());

    let guard = sink.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
    assert!(
      guard.fetch_errors.is_empty(),
      "dns failures should not be recorded as fetch errors"
    );
    assert!(
      guard.failure_stage.is_none(),
      "dns failures should not set failure_stage"
    );
  }

  #[test]
  fn css_import_fetcher_http_error_still_records_diagnostics() {
    let sink = Arc::new(Mutex::new(RenderDiagnostics::default()));
    let ctx = ResourceContext {
      document_url: Some("https://example.com/".to_string()),
      referrer_policy: Default::default(),
      policy: ResourceAccessPolicy::default(),
      csp: None,
      diagnostics: Some(SharedRenderDiagnostics {
        inner: Arc::clone(&sink),
      }),
      iframe_depth_remaining: None,
      iframe_embedder: None,
    };
    let loader = CssImportFetcher::new(
      Some("https://example.com/".to_string()),
      None,
      Arc::new(Http404Fetcher),
      Some(ctx),
      None,
      ReferrerPolicy::default(),
    );

    let result = loader.load("https://example.com/missing.css");
    assert!(result.is_err(), "expected 404 import to fail");

    let guard = sink.lock().unwrap_or_else(|poisoned| poisoned.into_inner());
    assert_eq!(guard.fetch_errors.len(), 1);
    assert_eq!(guard.fetch_errors[0].kind, ResourceKind::Stylesheet);
    assert_eq!(guard.fetch_errors[0].url, "https://example.com/missing.css");
    assert_eq!(guard.fetch_errors[0].status, Some(404));
    assert!(
      guard.failure_stage.is_none(),
      "stylesheet fetch errors should not mark the render as failed"
    );
  }

  #[derive(Clone, Default)]
  struct MapFetcher {
    map: HashMap<String, (Vec<u8>, Option<String>)>,
  }

  impl MapFetcher {
    fn with_entry(mut self, url: &str, css: &str) -> Self {
      self.map.insert(
        url.to_string(),
        (css.as_bytes().to_vec(), Some("text/css".to_string())),
      );
      self
    }
  }

  impl ResourceFetcher for MapFetcher {
    fn fetch(&self, url: &str) -> crate::error::Result<FetchedResource> {
      self
        .map
        .get(url)
        .map(|(bytes, content_type)| FetchedResource::new(bytes.clone(), content_type.clone()))
        .ok_or_else(|| {
          Error::Io(io::Error::new(
            io::ErrorKind::NotFound,
            format!("missing resource: {url}"),
          ))
        })
    }
  }

  #[derive(Clone, Default)]
  struct RecordingFetcher {
    map: HashMap<String, (Vec<u8>, Option<String>)>,
    fetched: Arc<Mutex<Vec<String>>>,
  }

  impl RecordingFetcher {
    fn with_entry(mut self, url: &str, css: &str) -> Self {
      self.map.insert(
        url.to_string(),
        (css.as_bytes().to_vec(), Some("text/css".to_string())),
      );
      self
    }

    fn fetched_urls(&self) -> Vec<String> {
      self
        .fetched
        .lock()
        .map(|guard| guard.clone())
        .unwrap_or_default()
    }
  }

  impl ResourceFetcher for RecordingFetcher {
    fn fetch(&self, url: &str) -> crate::error::Result<FetchedResource> {
      if let Ok(mut guard) = self.fetched.lock() {
        guard.push(url.to_string());
      }
      self
        .map
        .get(url)
        .map(|(bytes, content_type)| FetchedResource::new(bytes.clone(), content_type.clone()))
        .ok_or_else(|| {
          Error::Io(io::Error::new(
            io::ErrorKind::NotFound,
            format!("missing resource: {url}"),
          ))
        })
    }
  }

  #[derive(Clone, Default)]
  struct RecordingRequestFetcher {
    map: HashMap<String, (Vec<u8>, Option<String>, Option<String>)>,
    requests: Arc<Mutex<Vec<RecordedFetchRequest>>>,
  }

  #[derive(Debug, Clone, PartialEq, Eq)]
  struct RecordedFetchRequest {
    url: String,
    destination: FetchDestination,
    referrer_url: Option<String>,
    referrer_policy: ReferrerPolicy,
  }

  impl RecordingRequestFetcher {
    fn with_entry(mut self, url: &str, content: &str, content_type: &str) -> Self {
      self.map.insert(
        url.to_string(),
        (
          content.as_bytes().to_vec(),
          Some(content_type.to_string()),
          None,
        ),
      );
      self
    }

    fn with_entry_with_final_url(
      mut self,
      url: &str,
      content: &str,
      content_type: &str,
      final_url: &str,
    ) -> Self {
      self.map.insert(
        url.to_string(),
        (
          content.as_bytes().to_vec(),
          Some(content_type.to_string()),
          Some(final_url.to_string()),
        ),
      );
      self
    }

    fn requests(&self) -> Vec<RecordedFetchRequest> {
      self
        .requests
        .lock()
        .map(|guard| guard.clone())
        .unwrap_or_default()
    }
  }

  impl ResourceFetcher for RecordingRequestFetcher {
    fn fetch(&self, url: &str) -> crate::error::Result<FetchedResource> {
      self
        .map
        .get(url)
        .map(|(bytes, content_type, final_url)| {
          let mut resource = FetchedResource::new(bytes.clone(), content_type.clone());
          resource.final_url = final_url.clone();
          resource
        })
        .ok_or_else(|| {
          Error::Io(io::Error::new(
            io::ErrorKind::NotFound,
            format!("missing resource: {url}"),
          ))
        })
    }

    fn fetch_with_request(
      &self,
      request: FetchRequest<'_>,
    ) -> crate::error::Result<FetchedResource> {
      if let Ok(mut guard) = self.requests.lock() {
        guard.push(RecordedFetchRequest {
          url: request.url.to_string(),
          destination: request.destination,
          referrer_url: request.referrer_url.map(|r| r.to_string()),
          referrer_policy: request.referrer_policy,
        });
      }
      self.fetch(request.url)
    }
  }

  #[test]
  fn css_imports_use_importing_stylesheet_as_referrer_and_final_url_as_base() {
    let fetcher = Arc::new(
      RecordingRequestFetcher::default()
        .with_entry_with_final_url(
          "https://example.com/import.css",
          "@import \"nested.css\"; body { background-image: url(\"asset.png\"); }",
          "text/css",
          "https://cdn.example.com/dir/import.css",
        )
        .with_entry(
          "https://cdn.example.com/dir/nested.css",
          "body { color: red; }",
          "text/css",
        ),
    );
    let fetcher_for_loader: Arc<dyn ResourceFetcher> = fetcher.clone();
    let ctx = ResourceContext {
      document_url: Some("https://example.com/doc.html".to_string()),
      referrer_policy: Default::default(),
      policy: ResourceAccessPolicy::default(),
      csp: None,
      diagnostics: None,
      iframe_depth_remaining: None,
      iframe_embedder: None,
    };
    let loader = CssImportFetcher::new(
      Some("https://example.com/root.css".to_string()),
      None,
      fetcher_for_loader,
      Some(ctx),
      None,
      ReferrerPolicy::default(),
    );
    let media_ctx = MediaContext::screen(800.0, 600.0);
    let sheet = crate::css::parser::parse_stylesheet("@import \"import.css\";")
      .expect("parse root stylesheet");
    let resolved = sheet
      .resolve_imports_owned_with_cache(
        &loader,
        Some("https://example.com/root.css"),
        &media_ctx,
        None,
      )
      .expect("resolve imports");
    assert!(
      !resolved.contains_imports(),
      "resolved stylesheet should not contain remaining @import rules"
    );

    let requests = fetcher.requests();
    assert_eq!(requests.len(), 2);
    assert_eq!(requests[0].url, "https://example.com/import.css");
    assert_eq!(
      requests[0].referrer_url.as_deref(),
      Some("https://example.com/root.css")
    );
    assert_eq!(requests[1].url, "https://cdn.example.com/dir/nested.css");
    assert_eq!(
      requests[1].referrer_url.as_deref(),
      Some("https://cdn.example.com/dir/import.css")
    );
  }

  fn apply_styles_with_media_target_and_imports(
    dom: &DomNode,
    stylesheet: &StyleSheet,
    media_ctx: &MediaContext,
    target_fragment: Option<&str>,
    import_loader: Option<&dyn CssImportLoader>,
    base_url: Option<&str>,
    container_ctx: Option<&ContainerQueryContext>,
    container_scope: Option<&HashSet<usize>>,
    reuse_map: Option<&HashMap<usize, *const StyledNode>>,
  ) -> StyledNode {
    let style_set = StyleSet::from_document(stylesheet.clone());
    apply_style_set_with_media_target_and_imports_cached(
      dom,
      &style_set,
      media_ctx,
      target_fragment,
      import_loader,
      base_url,
      container_ctx,
      container_scope,
      reuse_map,
      None,
    )
  }

  fn snap_viewport(tree: &mut FragmentTree, scroll: Point) -> Point {
    crate::scroll::apply_scroll_snap(tree, &crate::scroll::ScrollState::with_viewport(scroll))
      .state
      .viewport
  }
  use image::codecs::png::PngEncoder;
  use image::load_from_memory;
  use image::ColorType;
  use image::ImageEncoder;
  use image::RgbaImage;

  fn text_color_for(tree: &FragmentTree, needle: &str) -> Option<Rgba> {
    tree.iter_fragments().find_map(|frag| match &frag.content {
      FragmentContent::Text { text, .. } if text.contains(needle) => {
        frag.style.as_ref().map(|s| s.color)
      }
      _ => None,
    })
  }

  fn text_width_for(tree: &FragmentTree, needle: &str) -> Option<f32> {
    tree.iter_fragments().find_map(|frag| match &frag.content {
      FragmentContent::Text { text, .. } if text.contains(needle) => Some(frag.bounds.width()),
      _ => None,
    })
  }

  fn styled_color_by_id(styled: &StyledNode, id: &str) -> Option<Rgba> {
    if styled.node.get_attribute("id").as_deref() == Some(id) {
      return Some(styled.styles.color);
    }
    styled
      .children
      .iter()
      .find_map(|child| styled_color_by_id(child, id))
  }

  fn find_styled_by_dom_id<'a>(styled: &'a StyledNode, id: &str) -> Option<&'a StyledNode> {
    if styled.node.get_attribute("id").as_deref() == Some(id) {
      return Some(styled);
    }

    styled
      .children
      .iter()
      .find_map(|child| find_styled_by_dom_id(child, id))
  }

  fn styled_node_id_by_id(styled: &StyledNode, id: &str) -> Option<usize> {
    if styled.node.get_attribute("id").as_deref() == Some(id) {
      return Some(styled.node_id);
    }
    styled
      .children
      .iter()
      .find_map(|child| styled_node_id_by_id(child, id))
  }

  fn styled_ancestor_ids(styled: &StyledNode, id: &str) -> Vec<usize> {
    fn helper<'a>(node: &'a StyledNode, id: &str, trail: &mut Vec<usize>) -> bool {
      if node.node.get_attribute("id").as_deref() == Some(id) {
        return true;
      }
      for child in node.children.iter() {
        trail.push(node.node_id);
        if helper(child, id, trail) {
          return true;
        }
        trail.pop();
      }
      false
    }

    let mut out = Vec::new();
    helper(styled, id, &mut out);
    out
  }

  fn find_dom_by_id<'a>(node: &'a DomNode, id: &str) -> Option<&'a DomNode> {
    if node.get_attribute_ref("id") == Some(id) {
      return Some(node);
    }
    node
      .children
      .iter()
      .find_map(|child| find_dom_by_id(child, id))
  }

  fn dom_equivalent(a: &DomNode, b: &DomNode) -> bool {
    fn node_type_equivalent(a: &DomNodeType, b: &DomNodeType) -> bool {
      match (a, b) {
        (
          DomNodeType::Document {
            quirks_mode: a,
            scripting_enabled: a_scripting,
            is_html_document: a_is_html_document,
          },
          DomNodeType::Document {
            quirks_mode: b,
            scripting_enabled: b_scripting,
            is_html_document: b_is_html_document,
          },
        ) => a == b && a_scripting == b_scripting && a_is_html_document == b_is_html_document,
        (
          DomNodeType::ShadowRoot {
            mode: a_mode,
            delegates_focus: a_focus,
          },
          DomNodeType::ShadowRoot {
            mode: b_mode,
            delegates_focus: b_focus,
          },
        ) => a_mode == b_mode && a_focus == b_focus,
        (
          DomNodeType::Slot {
            namespace: a_ns,
            attributes: a_attrs,
            assigned: a_assigned,
          },
          DomNodeType::Slot {
            namespace: b_ns,
            attributes: b_attrs,
            assigned: b_assigned,
          },
        ) => a_ns == b_ns && a_attrs == b_attrs && a_assigned == b_assigned,
        (
          DomNodeType::Element {
            tag_name: a_name,
            namespace: a_ns,
            attributes: a_attrs,
          },
          DomNodeType::Element {
            tag_name: b_name,
            namespace: b_ns,
            attributes: b_attrs,
          },
        ) => a_name == b_name && a_ns == b_ns && a_attrs == b_attrs,
        (DomNodeType::Text { content: a }, DomNodeType::Text { content: b }) => a == b,
        _ => false,
      }
    }

    if !node_type_equivalent(&a.node_type, &b.node_type) {
      return false;
    }
    if a.children.len() != b.children.len() {
      return false;
    }
    a.children
      .iter()
      .zip(b.children.iter())
      .all(|(a, b)| dom_equivalent(a, b))
  }

  fn accessibility_contains_id(node: &AccessibilityNode, id: &str) -> bool {
    if node.id.as_deref() == Some(id) {
      return true;
    }
    node
      .children
      .iter()
      .any(|child| accessibility_contains_id(child, id))
  }

  #[test]
  fn skips_top_layer_state_when_document_has_no_dialog_or_popover() {
    let mut renderer = FastRender::new().unwrap();
    let dom = renderer
      .parse_html("<div><p id=content>Hello</p></div>")
      .unwrap();
    let trace = TraceHandle::disabled();
    let _diagnostics_session = DiagnosticsSessionGuard::acquire();
    let mut stats = RenderStatsRecorder::new(DiagnosticsLevel::Basic);
    let scroll_state = ScrollState::default();
    let artifacts = renderer
      .layout_document_for_media_with_artifacts(
        &dom,
        None,
        200,
        200,
        MediaType::Screen,
        LayoutDocumentOptions::default(),
        &scroll_state,
        None,
        None,
        &trace,
        LayoutParallelism::default(),
        None,
        None,
        Some(&mut stats),
        None,
      )
      .unwrap();
    let stats = stats.finish();

    assert_eq!(
      stats.timings.dom_top_layer_ms, None,
      "expected top-layer state work to be skipped when no candidates exist"
    );
    assert!(
      dom_equivalent(&dom, &artifacts.dom),
      "DOM should be unchanged when no top-layer candidates exist"
    );
  }

  #[test]
  fn top_layer_state_applies_for_open_dialog_and_popover() {
    let renderer = FastRender::new().unwrap();
    let dom = renderer
      .parse_html(
        "<dialog id=dlg data-fastr-open=modal><div id=pop popover data-fastr-open=true>Pop</div></dialog><p id=outside>Outside</p>",
      )
      .unwrap();
    let trace = TraceHandle::disabled();
    let mut renderer = renderer;
    let _diagnostics_session = DiagnosticsSessionGuard::acquire();
    let mut stats = RenderStatsRecorder::new(DiagnosticsLevel::Basic);
    let scroll_state = ScrollState::default();
    let artifacts = renderer
      .layout_document_for_media_with_artifacts(
        &dom,
        None,
        200,
        200,
        MediaType::Screen,
        LayoutDocumentOptions::default(),
        &scroll_state,
        None,
        None,
        &trace,
        LayoutParallelism::default(),
        None,
        None,
        Some(&mut stats),
        None,
      )
      .unwrap();
    let stats = stats.finish();

    assert!(
      stats.timings.dom_top_layer_ms.is_some(),
      "expected top-layer state work to run when dialogs/popovers are present"
    );

    let dialog = find_dom_by_id(&artifacts.dom, "dlg").expect("dialog node");
    assert!(
      dialog.get_attribute_ref("open").is_some(),
      "expected dialog open state to be applied"
    );
    assert!(
      dialog.get_attribute_ref("data-fastr-inert").is_none(),
      "modal dialog subtree should not be inert"
    );

    let popover = find_dom_by_id(&artifacts.dom, "pop").expect("popover node");
    assert!(
      popover.get_attribute_ref("open").is_some(),
      "expected popover open state to be applied"
    );
    assert!(
      popover.get_attribute_ref("data-fastr-inert").is_none(),
      "popover inside modal subtree should not be inert"
    );

    let outside = find_dom_by_id(&artifacts.dom, "outside").expect("outside node");
    assert_eq!(
      outside.get_attribute_ref("data-fastr-inert"),
      Some("true"),
      "expected nodes outside the modal dialog to become inert"
    );

    let tree = renderer
      .accessibility_tree_with_options(&dom, RenderOptions::new().with_viewport(200, 200))
      .unwrap();
    assert!(
      !accessibility_contains_id(&tree, "outside"),
      "expected inert nodes outside the modal dialog to be suppressed from the accessibility tree"
    );
  }

  #[test]
  fn accessibility_tree_respects_stage_alloc_budget() {
    let mut renderer = FastRender::builder()
      .font_sources(FontConfig::bundled_only())
      .build()
      .unwrap();

    let css = format!(
      "/* accessibility_tree_respects_stage_alloc_budget */{}",
      ".a{color:red;}".repeat(128)
    );
    let html = format!("<!doctype html><style>{css}</style><div>Hello</div>");

    let err = renderer
      .accessibility_tree_html(
        &html,
        RenderOptions::new()
          .with_viewport(200, 200)
          .with_stage_alloc_budget_bytes(Some(1)),
      )
      .unwrap_err();

    match err {
      Error::Render(RenderError::StageAllocationBudgetExceeded { heartbeat, .. }) => {
        assert_eq!(heartbeat, crate::render_control::StageHeartbeat::CssParse);
      }
      other => panic!("expected StageAllocationBudgetExceeded, got {other:?}"),
    }
  }

  #[test]
  fn last_resort_fallback_samples_are_exposed_in_render_stats() {
    let _diagnostics_session = DiagnosticsSessionGuard::acquire();
    struct TextDiagnosticsGuard;

    impl Drop for TextDiagnosticsGuard {
      fn drop(&mut self) {
        let _ = crate::text::pipeline::take_text_diagnostics();
      }
    }

    crate::text::pipeline::enable_text_diagnostics();
    let _guard = TextDiagnosticsGuard;

    let font_context = FontContext::with_config(FontConfig::bundled_only());
    let db = font_context.database();

    let candidates = [
      '\u{10FFFF}',
      '\u{10FFFE}',
      '\u{FDD0}',
      '\u{E000}',
      '\u{0378}',
    ];
    let missing = candidates
      .into_iter()
      .find(|ch| !db.faces().any(|face| db.has_glyph_cached(face.id, *ch)))
      .expect("expected at least one missing glyph candidate in bundled fonts");

    let pipeline = ShapingPipeline::new();
    let style = ComputedStyle::default();
    let cluster = format!("{missing}\u{0301}");
    pipeline
      .shape(&cluster, &style, &font_context)
      .expect("shape run");

    let mut stats = RenderStats::default();
    merge_text_diagnostics(&mut stats);

    assert_eq!(stats.counts.last_resort_font_fallbacks, Some(1));
    assert_eq!(
      stats.counts.last_resort_font_fallback_samples,
      Some(vec![format!("U+{:04X} U+0301", missing as u32)])
    );
  }

  #[test]
  fn diagnostics_session_guard_recovers_from_poisoned_lock() {
    let result = std::panic::catch_unwind(|| {
      let _guard = DiagnosticsSessionGuard::acquire();
      panic!("poison the diagnostics session lock");
    });
    assert!(result.is_err(), "expected panic to be caught");
    assert!(
      diagnostics_session_mutex().is_poisoned(),
      "expected diagnostics session mutex to be poisoned after panic"
    );

    {
      let _guard = DiagnosticsSessionGuard::acquire();
    }
    assert!(
      diagnostics_session_mutex().is_poisoned(),
      "expected DiagnosticsSessionGuard to tolerate mutex poison"
    );
  }

  #[test]
  fn diagnostics_session_nested_acquire_is_reentrant() {
    let outer = DiagnosticsSessionGuard::acquire();
    let inner = DiagnosticsSessionGuard::acquire();

    let (ready_tx, ready_rx) = std::sync::mpsc::channel::<()>();
    let (acquired_tx, acquired_rx) = std::sync::mpsc::channel::<()>();

    let helper = std::thread::spawn(move || {
      ready_tx.send(()).expect("send ready");
      let _guard = DiagnosticsSessionGuard::acquire();
      acquired_tx.send(()).expect("send acquired");
    });

    ready_rx
      .recv_timeout(Duration::from_secs(1))
      .expect("expected helper thread to start");
    assert!(
      acquired_rx
        .recv_timeout(Duration::from_millis(200))
        .is_err(),
      "expected diagnostics session mutex to be held while nested guards are active"
    );

    drop(inner);
    assert!(
      acquired_rx
        .recv_timeout(Duration::from_millis(200))
        .is_err(),
      "expected diagnostics session mutex to remain held until the outermost guard is dropped"
    );

    drop(outer);
    acquired_rx
      .recv_timeout(Duration::from_secs(1))
      .expect("expected helper thread to acquire after outer guard is dropped");

    helper.join().expect("join helper thread");
  }

  #[test]
  fn diagnostics_are_per_render_and_do_not_leak_between_sequential_renders() {
    // Render 1:
    // - includes text so shaping runs
    // - uses flex layout so Taffy runs
    // - applies a blur filter so paint diagnostics hit the blur counters
    // - loads one external stylesheet so ResourceDiagnostics.fetch_counts is non-empty
    //
    // Render 2:
    // - no text and no flex/grid so shaping/Taffy/blur should be absent/zero
    // - no subresources so fetch_counts should be empty
    let mut fetcher = MapFetcher::default().with_entry(
      "https://example.com/style.css",
      r#"
        #container { display: flex; filter: blur(1px); background: rgb(0, 255, 0); }
        #container > div { flex: 1; }
      "#,
    );

    let fetcher = CachingFetcher::new(fetcher);
    let mut renderer = FastRender::builder()
      .font_sources(FontConfig::bundled_only())
      .fetcher(Arc::new(fetcher))
      .build()
      .unwrap();

    let options = RenderOptions::new()
      .with_viewport(64, 64)
      .with_diagnostics_level(DiagnosticsLevel::Basic)
      .with_runtime_toggles(RuntimeToggles::from_map(HashMap::from([(
        "FASTR_FETCH_LINK_CSS".to_string(),
        "1".to_string(),
      )])))
      // Keep diagnostics stable by forcing single-threaded layout/paint; many of the diagnostics
      // collectors are thread-local and are snapped from the caller thread.
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled());

    let html_with_text_and_flex = r#"<!DOCTYPE html>
<html>
  <head>
    <link rel="stylesheet" href="https://example.com/style.css">
  </head>
  <body>
    <div id="container">
      <div>Alpha</div>
      <div>Beta</div>
    </div>
  </body>
</html>"#;

    let stats1 = renderer
      .render_html_with_diagnostics(html_with_text_and_flex, options.clone())
      .unwrap()
      .diagnostics
      .stats
      .expect("expected RenderDiagnostics.stats when diagnostics are enabled");

    let stats2 = renderer
      .render_html_with_diagnostics("<div></div>", options)
      .unwrap()
      .diagnostics
      .stats
      .expect("expected RenderDiagnostics.stats when diagnostics are enabled");

    assert!(
      stats1.counts.shaped_runs.unwrap_or(0) > 0,
      "expected shaped_runs > 0 in first render, got {:?}",
      stats1.counts.shaped_runs
    );
    assert!(
      stats1.counts.glyphs.unwrap_or(0) > 0,
      "expected glyphs > 0 in first render, got {:?}",
      stats1.counts.glyphs
    );
    assert_eq!(
      stats2.counts.shaped_runs,
      Some(0),
      "expected shaped_runs to reset for second render"
    );
    assert_eq!(
      stats2.counts.glyphs,
      Some(0),
      "expected glyphs to reset for second render"
    );

    let taffy_nodes_total = stats1
      .layout
      .taffy_nodes_built
      .unwrap_or(0)
      .saturating_add(stats1.layout.taffy_nodes_reused.unwrap_or(0));
    assert!(
      taffy_nodes_total > 0,
      "expected Taffy to run in first render (nodes_built={:?} nodes_reused={:?})",
      stats1.layout.taffy_nodes_built,
      stats1.layout.taffy_nodes_reused
    );
    assert!(
      stats1.layout.taffy_flex_measure_calls.unwrap_or(0) > 0
        || stats1.layout.taffy_grid_measure_calls.unwrap_or(0) > 0,
      "expected Taffy measure calls in first render (flex={:?} grid={:?})",
      stats1.layout.taffy_flex_measure_calls,
      stats1.layout.taffy_grid_measure_calls
    );

    assert_eq!(
      stats2.layout.taffy_nodes_built,
      Some(0),
      "expected no Taffy nodes to be built in second render"
    );
    assert_eq!(
      stats2.layout.taffy_nodes_reused,
      Some(0),
      "expected no Taffy nodes to be reused in second render"
    );
    assert_eq!(
      stats2.layout.taffy_flex_compute_cpu_ms, None,
      "expected flex compute time to be absent in second render"
    );
    assert_eq!(
      stats2.layout.taffy_grid_compute_cpu_ms, None,
      "expected grid compute time to be absent in second render"
    );
    assert_eq!(
      stats2.layout.taffy_flex_measure_calls, None,
      "expected flex measure calls to be absent in second render"
    );
    assert_eq!(
      stats2.layout.taffy_grid_measure_calls, None,
      "expected grid measure calls to be absent in second render"
    );

    assert!(
      stats1.paint.blur_calls.unwrap_or(0) > 0,
      "expected blur_calls > 0 in first render, got {:?}",
      stats1.paint.blur_calls
    );
    assert_eq!(
      stats2.paint.blur_calls,
      Some(0),
      "expected paint blur calls to reset for second render"
    );

    assert!(
      stats1
        .resources
        .fetch_counts
        .get(&ResourceKind::Stylesheet)
        .copied()
        .unwrap_or(0)
        > 0,
      "expected external stylesheet fetch count to be recorded in first render"
    );
    assert!(
      stats2.resources.fetch_counts.is_empty(),
      "expected no subresource fetch counts in second render, got {:?}",
      stats2.resources.fetch_counts
    );

    assert!(
      stats1.resources.resource_cache_misses.unwrap_or(0) > 0,
      "expected resource cache misses > 0 in first render, got {:?}",
      stats1.resources.resource_cache_misses
    );
    assert_eq!(
      stats2.resources.resource_cache_misses,
      Some(0),
      "expected resource cache misses to reset for second render"
    );
  }

  #[test]
  fn stage_heartbeats_record_css_loading_between_dom_parse_and_cascade() {
    use crate::render_control::with_stage_listener;

    let stages: Arc<Mutex<Vec<StageHeartbeat>>> = Arc::new(Mutex::new(Vec::new()));
    let stages_for_listener = Arc::clone(&stages);
    let listener = Arc::new(move |stage: StageHeartbeat| {
      stages_for_listener.lock().unwrap().push(stage);
    });

    let fetcher = MapFetcher::default().with_entry(
      "https://example.com/style.css",
      "body { color: rgb(255, 0, 0); }",
    );
    let mut renderer = FastRender::builder()
      .base_url("https://example.com/")
      .fetcher(Arc::new(fetcher))
      .build()
      .unwrap();

    let html = r#"
      <!doctype html>
      <html>
        <head>
          <link rel="stylesheet" href="style.css">
        </head>
        <body>Hello</body>
      </html>
    "#;
    let _ = with_stage_listener(Some(listener), || {
      renderer.render_html(html, 10, 10).unwrap()
    });

    let stages = stages.lock().unwrap().clone();
    let dom_idx = stages
      .iter()
      .position(|stage| *stage == StageHeartbeat::DomParse)
      .expect(&format!(
        "expected DomParse stage heartbeat, got: {stages:?}"
      ));
    let css_idx = stages
      .iter()
      .enumerate()
      .skip(dom_idx + 1)
      .find_map(|(idx, stage)| (*stage == StageHeartbeat::CssInline).then_some(idx))
      .expect(&format!(
        "expected CssInline stage heartbeat after DomParse, got: {stages:?}"
      ));
    let cascade_idx = stages
      .iter()
      .enumerate()
      .skip(css_idx + 1)
      .find_map(|(idx, stage)| (*stage == StageHeartbeat::Cascade).then_some(idx))
      .expect(&format!(
        "expected Cascade stage heartbeat after CssInline, got: {stages:?}"
      ));

    assert!(
      dom_idx < css_idx,
      "expected DomParse stage before CssInline stage, got: {stages:?}"
    );
    assert!(
      css_idx < cascade_idx,
      "expected CssInline stage before Cascade stage, got: {stages:?}"
    );
  }

  #[test]
  fn prepare_html_with_stylesheets_inlines_linked_css() {
    #[derive(Clone, Default)]
    struct DeadlineAssertingFetcher {
      map: HashMap<String, (Vec<u8>, Option<String>)>,
      requested: Arc<Mutex<Vec<String>>>,
    }

    impl DeadlineAssertingFetcher {
      fn with_entry(mut self, url: &str, body: &str, content_type: &str) -> Self {
        self.map.insert(
          url.to_string(),
          (body.as_bytes().to_vec(), Some(content_type.to_string())),
        );
        self
      }

      fn requested_urls(&self) -> Vec<String> {
        self
          .requested
          .lock()
          .map(|guard| guard.clone())
          .unwrap_or_default()
      }
    }

    impl ResourceFetcher for DeadlineAssertingFetcher {
      fn fetch(&self, url: &str) -> crate::error::Result<FetchedResource> {
        assert!(
          crate::render_control::active_deadline().is_some(),
          "expected active render deadline in fetcher"
        );
        self
          .map
          .get(url)
          .map(|(bytes, content_type)| FetchedResource::new(bytes.clone(), content_type.clone()))
          .ok_or_else(|| {
            Error::Io(io::Error::new(
              io::ErrorKind::NotFound,
              format!("missing resource: {url}"),
            ))
          })
      }

      fn fetch_with_request(
        &self,
        request: FetchRequest<'_>,
      ) -> crate::error::Result<FetchedResource> {
        assert!(
          crate::render_control::active_deadline().is_some(),
          "expected active render deadline in fetcher"
        );
        if let Ok(mut guard) = self.requested.lock() {
          guard.push(request.url.to_string());
        }
        self.fetch(request.url)
      }
    }

    let html = r#"<!doctype html>
      <html><head>
        <link rel="stylesheet" href="/style.css">
      </head>
      <body>Hello</body>
      </html>"#;
    let base_hint = "https://example.com/page.html";
    let stylesheet_url = "https://example.com/style.css";

    let fetcher = Arc::new(DeadlineAssertingFetcher::default().with_entry(
      stylesheet_url,
      "html, body { margin: 0; background: black; }",
      "text/css",
    ));
    let config = FastRenderConfig::default()
      .with_font_sources(FontConfig::bundled_only())
      .with_paint_parallelism(PaintParallelism::disabled())
      .with_layout_parallelism(LayoutParallelism::disabled());
    let mut renderer = FastRender::with_config_and_fetcher(
      config,
      Some(fetcher.clone() as Arc<dyn ResourceFetcher>),
    )
    .unwrap();

    // Baseline: no inlining, so the linked stylesheet is ignored (relative URL without base).
    let mut baseline_renderer = FastRender::with_config(FastRenderConfig {
      font_config: FontConfig::bundled_only(),
      paint_parallelism: PaintParallelism::disabled(),
      layout_parallelism: LayoutParallelism::disabled(),
      ..FastRenderConfig::default()
    })
    .unwrap();
    let baseline_doc = baseline_renderer
      .prepare_html(html, RenderOptions::new().with_viewport(32, 32))
      .unwrap();
    let baseline = baseline_doc.paint_default().unwrap();
    assert_eq!(pix_rgba(&baseline, 0, 0), (255, 255, 255, 255));

    let prepared = renderer
      .prepare_html_with_stylesheets(html, base_hint, RenderOptions::new().with_viewport(32, 32))
      .unwrap();
    let painted = prepared.document.paint_default().unwrap();
    assert_eq!(pix_rgba(&painted, 0, 0), (0, 0, 0, 255));
    assert_eq!(fetcher.requested_urls(), vec![stylesheet_url.to_string()]);
  }

