  #[test]
  fn resolve_intrinsic_sizes_does_not_probe_invalid_video_poster() {
    #[derive(Clone)]
    struct PanicFetcher;

    impl ResourceFetcher for PanicFetcher {
      fn fetch(&self, _url: &str) -> Result<FetchedResource> {
        panic!("invalid video poster should not be fetched/probed");
      }
    }

    let renderer = FastRender::builder()
      .fetcher(Arc::new(PanicFetcher) as Arc<dyn ResourceFetcher>)
      .build()
      .expect("init renderer");
    let style = Arc::new(ComputedStyle::default());
    let mut node = BoxNode::new_replaced(
      style,
      ReplacedType::Video {
        src: String::new(),
        poster: Some("   ".to_string()),
        crossorigin: CrossOriginAttribute::None,
        referrer_policy: None,
        controls: false,
      },
      Some(Size::new(200.0, 0.0)),
      None,
    );

    renderer.resolve_replaced_intrinsic_sizes(&mut node, Size::new(800.0, 600.0));

    let replaced = match &node.box_type {
      BoxType::Replaced(replaced) => replaced,
      other => panic!("expected replaced box, got {other:?}"),
    };
    assert_eq!(replaced.intrinsic_size, Some(Size::new(200.0, 0.0)));
    assert_eq!(replaced.aspect_ratio, None);
  }

  #[test]
  fn resolve_intrinsic_sizes_handles_embed_and_object_svg() {
    let renderer = FastRender::new().expect("init renderer");
    let svg = "<svg xmlns='http://www.w3.org/2000/svg' width='16' height='10'></svg>";

    let mut embed_node = BoxNode::new_replaced(
      Arc::new(ComputedStyle::default()),
      ReplacedType::Embed {
        src: svg.to_string(),
      },
      None,
      None,
    );
    renderer.resolve_replaced_intrinsic_sizes(&mut embed_node, Size::new(800.0, 600.0));
    let embed_replaced = match embed_node.box_type {
      BoxType::Replaced(ref r) => r,
      _ => panic!("not replaced"),
    };
    assert_eq!(
      embed_replaced.intrinsic_size,
      Some(Size::new(16.0, 10.0)),
      "embed should pick intrinsic size from SVG"
    );
    assert_eq!(
      embed_replaced.aspect_ratio,
      Some(16.0 / 10.0),
      "embed should set aspect ratio from SVG"
    );

    let mut object_node = BoxNode::new_replaced(
      Arc::new(ComputedStyle::default()),
      ReplacedType::Object {
        data: svg.to_string(),
      },
      None,
      None,
    );
    renderer.resolve_replaced_intrinsic_sizes(&mut object_node, Size::new(800.0, 600.0));
    let object_replaced = match object_node.box_type {
      BoxType::Replaced(ref r) => r,
      _ => panic!("not replaced"),
    };
    assert_eq!(
      object_replaced.intrinsic_size,
      Some(Size::new(16.0, 10.0)),
      "object should pick intrinsic size from SVG"
    );
    assert_eq!(
      object_replaced.aspect_ratio,
      Some(16.0 / 10.0),
      "object should set aspect ratio from SVG"
    );
  }

  #[test]
  fn scroll_snap_changes_fingerprint() {
    let a = ComputedStyle::default();
    let mut b = a.clone();

    b.scroll_snap_type.axis = crate::style::types::ScrollSnapAxis::X;
    b.scroll_snap_type.strictness = crate::style::types::ScrollSnapStrictness::Mandatory;
    b.scroll_snap_align.inline = crate::style::types::ScrollSnapAlign::Center;
    b.scroll_snap_stop = crate::style::types::ScrollSnapStop::Always;

    let hash_a = style_layout_fingerprint(&a);
    let hash_b = style_layout_fingerprint(&b);

    assert_ne!(
      hash_a, hash_b,
      "scroll snap settings must influence layout fingerprints"
    );
  }

  #[test]
  fn calc_lengths_change_layout_fingerprint() {
    let mut a = ComputedStyle::default();
    let mut b = a.clone();

    let percent =
      crate::style::values::CalcLength::single(crate::style::values::LengthUnit::Percent, 10.0);
    let calc_a =
      crate::style::values::CalcLength::single(crate::style::values::LengthUnit::Px, 10.0)
        .add_scaled(&percent, 1.0)
        .expect("calc terms");
    let calc_b =
      crate::style::values::CalcLength::single(crate::style::values::LengthUnit::Px, 20.0)
        .add_scaled(&percent, 1.0)
        .expect("calc terms");

    a.width = Some(Length::calc(calc_a));
    b.width = Some(Length::calc(calc_b));

    assert_ne!(
      style_layout_fingerprint(&a),
      style_layout_fingerprint(&b),
      "distinct calc() expressions must influence layout fingerprints"
    );
  }

  #[test]
  fn layout_fingerprint_canonicalizes_negative_zero() {
    let mut style_zero = ComputedStyle::default();
    style_zero.width = Some(Length::px(0.0));
    let mut style_neg_zero = style_zero.clone();
    style_neg_zero.width = Some(Length::px(-0.0));

    assert_eq!(
      style_layout_fingerprint(&style_zero),
      style_layout_fingerprint(&style_neg_zero),
      "negative zero lengths should not affect layout fingerprints"
    );
  }

  #[test]
  fn individual_transforms_change_fingerprint() {
    let base = ComputedStyle::default();
    let base_hash = style_layout_fingerprint(&base);

    let mut translated = base.clone();
    translated.translate = crate::css::types::TranslateValue::Values {
      x: Length::px(10.0),
      y: Length::px(0.0),
      z: Length::px(0.0),
    };
    assert_ne!(
      base_hash,
      style_layout_fingerprint(&translated),
      "translate must influence layout fingerprints"
    );

    let mut rotated = base.clone();
    rotated.rotate = crate::css::types::RotateValue::Angle(45.0);
    assert_ne!(
      base_hash,
      style_layout_fingerprint(&rotated),
      "rotate must influence layout fingerprints"
    );

    let mut scaled = base.clone();
    scaled.scale = crate::css::types::ScaleValue::Values {
      x: 2.0,
      y: 1.0,
      z: 1.0,
    };
    assert_ne!(
      base_hash,
      style_layout_fingerprint(&scaled),
      "scale must influence layout fingerprints"
    );
  }

  #[test]
  fn scroll_snap_mandatory_adjusts_offsets() {
    let mut renderer = FastRender::new().unwrap();
    let html = r"
            <style>
                html, body { margin: 0; height: 100%; scroll-snap-type: y mandatory; }
                section { height: 200px; scroll-snap-align: start; }
            </style>
            <section></section>
            <section></section>
        ";

    let dom = renderer.parse_html(html).unwrap();
    let mut fragments = renderer.layout_document(&dom, 100, 100).unwrap();

    let snapped = snap_viewport(&mut fragments, Point::new(0.0, 120.0));
    assert!(
      (snapped.y - 200.0).abs() < 0.1,
      "expected snap to the second section"
    );
    assert!(snapped.x.abs() < 0.1);
  }

  #[test]
  fn prepared_document_paint_returns_applied_scroll_state() {
    let mut renderer = FastRender::new().unwrap();
    let html = r"
            <style>
                html, body { margin: 0; height: 100%; scroll-snap-type: y mandatory; }
                section { height: 100px; scroll-snap-align: start; }
            </style>
            <section></section>
            <section></section>
            <section></section>
        ";

    let prepared = renderer
      .prepare_html(html, RenderOptions::new().with_viewport(100, 100))
      .unwrap();

    let requested = 60.0;
    let frame = prepared
      .paint_with_options_frame(PreparedPaintOptions::default().with_scroll(0.0, requested))
      .unwrap();

    assert!(
      (frame.scroll_state.viewport.y - 100.0).abs() < 0.1,
      "expected scroll-snap to snap to y=100, got {:?} (requested y={requested})",
      frame.scroll_state.viewport
    );
  }

