  #[test]
  fn fetch_link_css_toggle_disables_linked_stylesheets_via_builder() {
    let base_url = "https://example.com/page.html";
    let fetcher = Arc::new(
      RecordingFetcher::default()
        .with_entry("https://example.com/a.css", "div { color: rgb(1, 2, 3); }"),
    );

    let toggles = RuntimeToggles::from_map(HashMap::from([(
      "FASTR_FETCH_LINK_CSS".to_string(),
      "0".to_string(),
    )]));
    let mut renderer = FastRender::builder()
      .base_url(base_url.to_string())
      .fetcher(fetcher.clone() as Arc<dyn ResourceFetcher>)
      .runtime_toggles(toggles)
      .build()
      .unwrap();

    let html = r#"
      <style>div { color: rgb(200, 0, 0); }</style>
      <link rel="stylesheet" href="a.css">
      <div>Link toggle</div>
    "#;
    let dom = renderer.parse_html(html).unwrap();
    let tree = renderer.layout_document(&dom, 200, 200).unwrap();

    let fetched_urls = fetcher.fetched_urls();
    assert!(
      !fetched_urls.contains(&"https://example.com/a.css".to_string()),
      "expected linked stylesheet fetch to be suppressed when FASTR_FETCH_LINK_CSS=0; fetched={fetched_urls:?}"
    );

    let color = text_color_for(&tree, "Link toggle").unwrap();
    assert_eq!(color, Rgba::rgb(200, 0, 0));
  }

  #[test]
  fn fetch_link_css_toggle_controls_inline_stylesheets_for_document() {
    let base_url = "https://example.com/page.html";
    let html = r#"<link rel="stylesheet" href="a.css"><div>Inline</div>"#;

    let fetcher = Arc::new(
      RecordingFetcher::default()
        .with_entry("https://example.com/a.css", "div { color: rgb(1, 2, 3); }"),
    );
    let renderer = FastRender::builder()
      .fetcher(fetcher.clone() as Arc<dyn ResourceFetcher>)
      .runtime_toggles(RuntimeToggles::from_map(HashMap::from([(
        "FASTR_FETCH_LINK_CSS".to_string(),
        "0".to_string(),
      )])))
      .build()
      .unwrap();

    let mut diagnostics = RenderDiagnostics::default();
    let output = renderer
      .inline_stylesheets_for_document(
        html,
        base_url,
        MediaType::Screen,
        None,
        &mut diagnostics,
        None,
      )
      .unwrap();
    assert_eq!(output, html.to_string());
    assert!(
      fetcher.fetched_urls().is_empty(),
      "expected inline_stylesheets_for_document to skip fetches when FASTR_FETCH_LINK_CSS=0"
    );

    let fetcher = Arc::new(
      RecordingFetcher::default()
        .with_entry("https://example.com/a.css", "div { color: rgb(1, 2, 3); }"),
    );
    let renderer = FastRender::builder()
      .fetcher(fetcher.clone() as Arc<dyn ResourceFetcher>)
      .runtime_toggles(RuntimeToggles::from_map(HashMap::from([(
        "FASTR_FETCH_LINK_CSS".to_string(),
        "1".to_string(),
      )])))
      .build()
      .unwrap();

    let mut diagnostics = RenderDiagnostics::default();
    let output = renderer
      .inline_stylesheets_for_document(
        html,
        base_url,
        MediaType::Screen,
        None,
        &mut diagnostics,
        None,
      )
      .unwrap();
    assert!(
      output.starts_with("<style>"),
      "expected inline stylesheet injection when FASTR_FETCH_LINK_CSS=1 (output={output:?})"
    );
    assert_eq!(
      fetcher.fetched_urls(),
      vec!["https://example.com/a.css".to_string()],
      "expected linked stylesheet to be fetched once when FASTR_FETCH_LINK_CSS=1"
    );
  }

  #[test]
  fn inline_stylesheets_rejects_crossorigin_stylesheets_without_acao_when_enforced() {
    #[derive(Debug, Clone, PartialEq, Eq)]
    struct RecordedRequest {
      url: String,
      destination: FetchDestination,
      referrer: Option<String>,
      client_origin: Option<DocumentOrigin>,
      credentials_mode: FetchCredentialsMode,
    }

    #[derive(Default)]
    struct CorsBlockingFetcher {
      requests: Mutex<Vec<RecordedRequest>>,
    }

    impl CorsBlockingFetcher {
      fn requests(&self) -> Vec<RecordedRequest> {
        self
          .requests
          .lock()
          .map(|guard| guard.clone())
          .unwrap_or_default()
      }
    }

    impl ResourceFetcher for CorsBlockingFetcher {
      fn fetch(&self, _url: &str) -> crate::error::Result<FetchedResource> {
        panic!("expected inline stylesheet loader to use fetch_with_request");
      }

      fn fetch_with_request(
        &self,
        request: FetchRequest<'_>,
      ) -> crate::error::Result<FetchedResource> {
        if let Ok(mut guard) = self.requests.lock() {
          guard.push(RecordedRequest {
            url: request.url.to_string(),
            destination: request.destination,
            referrer: request.referrer_url.map(|r| r.to_string()),
            client_origin: request.client_origin.cloned(),
            credentials_mode: request.credentials_mode,
          });
        }

        let mut res = FetchedResource::new(
          b"body { color: rgb(1, 2, 3); }".to_vec(),
          Some("text/css".to_string()),
        );
        res.status = Some(200);
        res.final_url = Some(request.url.to_string());
        // Intentionally omit Access-Control-Allow-Origin so CORS validation rejects.
        Ok(res)
      }
    }

    let html =
      r#"<link rel="stylesheet" crossorigin href="https://cdn.test/a.css"><div>Inline</div>"#;
    let document_url = "https://example.com/page.html";
    let stylesheet_url = "https://cdn.test/a.css";

    let fetcher = CorsBlockingFetcher::default();
    let origin = origin_from_url(document_url).expect("origin");
    let expected_origin = origin.clone();
    let ctx = ResourceContext {
      document_url: Some(document_url.to_string()),
      referrer_policy: ReferrerPolicy::default(),
      policy: ResourceAccessPolicy {
        document_origin: Some(origin),
        ..ResourceAccessPolicy::default()
      },
      csp: None,
      diagnostics: None,
      iframe_depth_remaining: None,
      iframe_embedder: None,
    };

    let mut diagnostics = RenderDiagnostics::default();
    let toggles = crate::debug::runtime::RuntimeToggles::from_map(HashMap::from([(
      "FASTR_FETCH_ENFORCE_CORS".to_string(),
      "1".to_string(),
    )]));

    crate::debug::runtime::with_thread_runtime_toggles(Arc::new(toggles), || {
      let output = FastRender::inline_stylesheets_for_html_with_context_with_budget(
        &fetcher,
        html,
        document_url,
        MediaType::Screen,
        None,
        Some(&ctx),
        &mut diagnostics,
        None,
        None,
        StylesheetInlineBudget::default(),
      )
      .expect("inline stylesheets");
      assert_eq!(
        output,
        html.to_string(),
        "expected cross-origin stylesheet to be skipped due to CORS"
      );
    });

    let requests = fetcher.requests();
    assert_eq!(requests.len(), 1, "expected a single stylesheet fetch");
    assert_eq!(requests[0].url, stylesheet_url);
    assert_eq!(requests[0].destination, FetchDestination::StyleCors);
    assert_eq!(requests[0].referrer.as_deref(), Some(document_url));
    assert_eq!(requests[0].client_origin, Some(expected_origin));
    assert_eq!(
      requests[0].credentials_mode,
      FetchCredentialsMode::SameOrigin
    );

    assert_eq!(diagnostics.fetch_errors.len(), 1);
    assert!(
      diagnostics.fetch_errors[0]
        .message
        .to_ascii_lowercase()
        .contains("blocked by cors"),
      "unexpected diagnostics entry: {:?}",
      diagnostics.fetch_errors[0]
    );
  }

  #[test]
  fn diagnostics_records_stylesheet_fetches_and_css_parse_ms() {
    let base_url = "https://example.com/page.html";
    let fetcher = MapFetcher::default()
      .with_entry(
        "https://example.com/style.css",
        "@import \"import.css\";\nbody { color: rgb(1, 2, 3); }",
      )
      .with_entry(
        "https://example.com/import.css",
        "body { background: rgb(4, 5, 6); }",
      );

    let mut renderer = FastRender::builder()
      .base_url(base_url.to_string())
      .fetcher(Arc::new(fetcher) as Arc<dyn ResourceFetcher>)
      .build()
      .unwrap();

    let html = r#"
      <link rel="stylesheet" href="style.css">
      <div>hello</div>
    "#;

    let options = RenderOptions::new()
      .with_viewport(200, 200)
      .with_diagnostics_level(DiagnosticsLevel::Basic);
    let result = renderer
      .render_html_with_diagnostics(html, options)
      .expect("render with diagnostics");
    let stats = result.diagnostics.stats.expect("stats should be populated");

    let stylesheet_fetches = stats
      .resources
      .fetch_counts
      .get(&ResourceKind::Stylesheet)
      .copied()
      .unwrap_or(0);
    assert_eq!(
      stylesheet_fetches, 2,
      "expected one external stylesheet + one @import load"
    );
    assert!(
      stats.timings.css_inlining_ms.is_some(),
      "css_inlining_ms should be populated"
    );
    assert!(
      stats.timings.css_parse_ms.is_some(),
      "css_parse_ms should be populated"
    );
  }

